{
  "name": "Lógica Interactiva: Ordenamiento de Información",
  "description": "Una aplicación educativa para estudiantes de séptimo grado diseñada para aprender a organizar información de forma lógica (horizontal, vertical, circular y tablas) a través de simulaciones interactivas."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum View {
  WELCOME = 'WELCOME',
  THEORY = 'THEORY',
  HORIZONTAL = 'HORIZONTAL',
  VERTICAL = 'VERTICAL',
  CIRCULAR = 'CIRCULAR',
  TABLE = 'TABLE',
  CHALLENGE = 'CHALLENGE'
}

export interface Problem {
  id: number;
  title: string;
  description: string;
  options: string[];
  correctAnswer: string;
  explanation: string;
  type: View;
}

export interface Person {
  id: string;
  name: string;
  color: string;
}

import React, { useState } from 'react';
import { View } from './types';
import Welcome from './components/Welcome';
import Theory from './components/Theory';
import HorizontalOrdering from './components/HorizontalOrdering';
import VerticalOrdering from './components/VerticalOrdering';
import CircularOrdering from './components/CircularOrdering';
import TableOrdering from './components/TableOrdering';
import Challenge from './components/Challenge';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.WELCOME);

  const renderView = () => {
    switch (currentView) {
      case View.WELCOME:
        return <Welcome onStart={() => setCurrentView(View.THEORY)} />;
      case View.THEORY:
        return <Theory onNext={() => setCurrentView(View.HORIZONTAL)} />;
      case View.HORIZONTAL:
        return <HorizontalOrdering onNext={() => setCurrentView(View.VERTICAL)} />;
      case View.VERTICAL:
        return <VerticalOrdering onNext={() => setCurrentView(View.CIRCULAR)} />;
      case View.CIRCULAR:
        return <CircularOrdering onNext={() => setCurrentView(View.TABLE)} />;
      case View.TABLE:
        return <TableOrdering onNext={() => setCurrentView(View.CHALLENGE)} />;
      case View.CHALLENGE:
        return <Challenge onRestart={() => setCurrentView(View.WELCOME)} />;
      default:
        return <Welcome onStart={() => setCurrentView(View.THEORY)} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      <div className="absolute inset-0 bg-pattern -z-10"></div>

      {/* Navigation Header */}
      {currentView !== View.WELCOME && (
        <header className="bg-white/80 backdrop-blur-md sticky top-0 z-50 shadow-sm border-b border-purple-100">
          <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
            <button 
              onClick={() => setCurrentView(View.WELCOME)}
              className="flex items-center gap-2 text-purple-600 font-bold text-xl"
            >
              <i className="fas fa-brain"></i>
              <span>Lógica <span className="text-blue-500">7°</span></span>
            </button>
            <nav className="hidden md:flex gap-4">
              {[
                { label: 'Teoría', view: View.THEORY },
                { label: 'Horizontal', view: View.HORIZONTAL },
                { label: 'Vertical', view: View.VERTICAL },
                { label: 'Circular', view: View.CIRCULAR },
                { label: 'Tablas', view: View.TABLE },
                { label: 'Reto Final', view: View.CHALLENGE },
              ].map((item) => (
                <button
                  key={item.view}
                  onClick={() => setCurrentView(item.view)}
                  className={`px-3 py-1 rounded-full text-sm font-medium transition-all ${
                    currentView === item.view 
                      ? 'bg-purple-600 text-white' 
                      : 'text-gray-600 hover:bg-purple-50'
                  }`}
                >
                  {item.label}
                </button>
              ))}
            </nav>
          </div>
        </header>
      )}

      <main className="flex-grow container mx-auto px-4 py-8">
        {renderView()}
      </main>

      <Footer />
    </div>
  );
};

export default App;

