export default Welcome;

import React, { useState } from 'react';
import { Person } from '../types';

interface Props {
  onNext: () => void;
}

const INITIAL_PEOPLE: Person[] = [
  { id: '1', name: 'María', color: 'bg-red-400' },
  { id: '2', name: 'Juana', color: 'bg-blue-400' },
  { id: '3', name: 'Ana', color: 'bg-green-400' },
  { id: '4', name: 'Inés', color: 'bg-yellow-400' },
  { id: '5', name: 'Enma', color: 'bg-pink-400' },
];

const HorizontalOrdering: React.FC<Props> = ({ onNext }) => {
  const [slots, setSlots] = useState<(Person | null)[]>(Array(5).fill(null));
  const [available, setAvailable] = useState<Person[]>(INITIAL_PEOPLE);
  const [feedback, setFeedback] = useState<string | null>(null);

  const handlePlace = (person: Person, index: number) => {
    const newSlots = [...slots];
    const oldPerson = newSlots[index];

    newSlots[index] = person;
    setSlots(newSlots);

    setAvailable(prev => {
      const filtered = prev.filter(p => p.id !== person.id);
      if (oldPerson) return [...filtered, oldPerson];
      return filtered;
    });
  };

  const reset = () => {
    setSlots(Array(5).fill(null));
    setAvailable(INITIAL_PEOPLE);
    setFeedback(null);
  };

  const check = () => {
    // Correct Order (Youngest to Oldest): Inés, Enma, Ana, Juana, María
    // Based on text: "María mayor que Juana. Ana joven que Juana pero mayor que Inés. Inés joven que Enma"
    const correctNames = ['Inés', 'Enma', 'Ana', 'Juana', 'María'];
    const currentNames = slots.map(s => s?.name);

    if (currentNames.every((name, i) => name === correctNames[i])) {
      setFeedback("¡Excelente! Has ordenado correctamente de menor a mayor.");
    } else {
      setFeedback("Casi lo tienes. Revisa los datos: 'María es la mayor de todas' e 'Inés es la más joven'.");
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-purple-100">
        <header className="mb-8">
          <span className="text-xs font-bold uppercase tracking-widest text-purple-400">Simulación Interactiva #1</span>
          <h2 className="text-3xl font-bold text-purple-700">Ordenamiento Horizontal</h2>
          <p className="text-gray-600 mt-2">
            <strong>Reto:</strong> Ordena de <strong>Menor (Izquierda)</strong> a <strong>Mayor (Derecha)</strong> de edad.
          </p>
          <div className="bg-purple-50 border-l-4 border-purple-400 p-4 mt-4 text-sm italic text-gray-700">
            "María es mucho mayor que Juana. Ana es más joven que Juana pero mucho mayor que Inés e Inés es más joven que Enma."
          </div>
        </header>

        <div className="flex flex-wrap gap-4 justify-center mb-12 min-h-[80px]">
          {available.map(p => (
            <button
              key={p.id}
              onClick={() => {
                const emptyIdx = slots.findIndex(s => s === null);
                if (emptyIdx !== -1) handlePlace(p, emptyIdx);
              }}
              className={`${p.color} text-white px-6 py-3 rounded-2xl shadow-md font-bold hover:scale-105 transition-transform`}
            >
              {p.name}
            </button>
          ))}
        </div>

        <div className="relative mb-12">
          <div className="h-2 bg-gray-200 w-full rounded-full absolute top-1/2 -translate-y-1/2"></div>
          <div className="flex justify-between relative z-10 px-4">
            {slots.map((s, i) => (
              <div key={i} className="flex flex-col items-center">
                <div 
                  onClick={() => {
                    if (s) {
                      setSlots(prev => {
                        const next = [...prev];
                        next[i] = null;
                        return next;
                      });
                      setAvailable(prev => [...prev, s]);
                    }
                  }}
                  className={`w-16 h-16 md:w-20 md:h-20 rounded-full border-4 border-dashed border-purple-200 flex items-center justify-center cursor-pointer transition-all ${s ? 'border-solid border-purple-500 scale-110' : 'hover:border-purple-300'}`}
                >
                  {s ? (
                    <div className={`${s.color} w-full h-full rounded-full flex items-center justify-center text-white font-bold text-xs md:text-sm`}>
                      {s.name}
                    </div>
                  ) : (
                    <span className="text-gray-300 text-xs">Pos. {i+1}</span>
                  )}
                </div>
                <span className="mt-2 text-[10px] uppercase font-bold text-gray-400">
                  {i === 0 ? 'Más Joven' : i === 4 ? 'Más Mayor' : ''}
                </span>
              </div>
            ))}
          </div>
        </div>

        {feedback && (
          <div className={`p-4 rounded-xl mb-6 text-center font-bold ${feedback.includes('Excelente') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center">
          <button onClick={reset} className="text-gray-500 hover:text-purple-600 font-bold transition-colors">
            <i className="fas fa-undo mr-2"></i> Reiniciar
          </button>
          <div className="flex gap-4">
            <button onClick={check} className="px-6 py-2 bg-blue-500 text-white rounded-xl font-bold hover:bg-blue-600 shadow-md">
              Verificar
            </button>
            <button onClick={onNext} className="px-6 py-2 bg-purple-600 text-white rounded-xl font-bold hover:bg-purple-700 shadow-md">
              Siguiente <i className="fas fa-arrow-right ml-2"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HorizontalOrdering;

import React, { useState } from 'react';
import { Person } from '../types';

interface Props {
  onNext: () => void;
}

const PEOPLE: Person[] = [
  { id: 'p1', name: 'Raúl', color: 'bg-orange-400' },
  { id: 'p2', name: 'Pedro', color: 'bg-indigo-400' },
  { id: 'p3', name: 'Carlos', color: 'bg-emerald-400' },
  { id: 'p4', name: 'Julio', color: 'bg-rose-400' },
];

const VerticalOrdering: React.FC<Props> = ({ onNext }) => {
  const [floors, setFloors] = useState<(Person | null)[]>(Array(4).fill(null));
  const [available, setAvailable] = useState<Person[]>(PEOPLE);
  const [feedback, setFeedback] = useState<string | null>(null);

  const handlePlace = (person: Person, floorIdx: number) => {
    const newFloors = [...floors];
    const oldPerson = newFloors[floorIdx];
    newFloors[floorIdx] = person;
    setFloors(newFloors);
    setAvailable(prev => {
      const filtered = prev.filter(p => p.id !== person.id);
      if (oldPerson) return [...filtered, oldPerson];
      return filtered;
    });
  };

  const check = () => {
    // Building structure (Bottom to Top):
    // 1. Raúl vive en el 1er piso.
    // 2. Pedro vive más abajo que Carlos.
    // 3. Julio vive un piso más arriba que Pedro.
    // Correct Order: 1: Raúl, 2: Pedro, 3: Julio, 4: Carlos
    const correctNames = ['Raúl', 'Pedro', 'Julio', 'Carlos'];
    const currentNames = floors.map(f => f?.name);

    if (currentNames.every((name, i) => name === correctNames[i])) {
      setFeedback("¡Correcto! Julio vive en el 3er piso.");
    } else {
      setFeedback("Revisa bien: Raúl va en el primero, y Julio vive justo arriba de Pedro.");
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-blue-100">
        <header className="mb-8">
          <span className="text-xs font-bold uppercase tracking-widest text-blue-400">Simulación Interactiva #2</span>
          <h2 className="text-3xl font-bold text-blue-700">Ordenamiento Vertical</h2>
          <p className="text-gray-600 mt-2">
            Ubica a los amigos en sus pisos correspondientes.
          </p>
          <div className="bg-blue-50 border-l-4 border-blue-400 p-4 mt-4 text-sm italic text-gray-700">
            "Los primos viven en un edificio de 4 pisos. Raúl vive en el primer piso. Pedro vive más abajo que Carlos y Julio vive un piso más arriba que Pedro. ¿Quién vive en el 3er piso?"
          </div>
        </header>

        <div className="flex flex-col md:flex-row gap-12 items-center justify-center">
          {/* Building Representation */}
          <div className="w-full md:w-64 bg-gray-100 p-4 rounded-3xl border-8 border-gray-200 shadow-inner">
            {[3, 2, 1, 0].map(idx => (
              <div 
                key={idx} 
                onClick={() => {
                  if (floors[idx]) {
                    setAvailable(prev => [...prev, floors[idx]!]);
                    setFloors(prev => {
                      const next = [...prev];
                      next[idx] = null;
                      return next;
                    });
                  }
                }}
                className={`h-24 mb-2 last:mb-0 rounded-xl border-2 border-dashed flex items-center justify-center cursor-pointer transition-all ${floors[idx] ? 'bg-white border-blue-400 shadow-md' : 'border-gray-300 hover:border-blue-300'}`}
              >
                {floors[idx] ? (
                  <div className={`flex items-center gap-3 ${floors[idx]?.color} text-white px-4 py-2 rounded-lg font-bold w-full mx-2 justify-center`}>
                    <i className="fas fa-user"></i>
                    {floors[idx]?.name}
                  </div>
                ) : (
                  <span className="text-gray-300 font-bold">Piso {idx + 1}</span>
                )}
              </div>
            ))}
            <div className="h-4 bg-gray-400 rounded-full mt-4 w-1/2 mx-auto"></div>
          </div>

          {/* Friends List */}
          <div className="flex flex-col gap-4">
            <h4 className="font-bold text-gray-500 uppercase text-xs tracking-widest">Amigos por ubicar:</h4>
            {available.map(p => (
              <button
                key={p.id}
                onClick={() => {
                  const emptyIdx = floors.findIndex(f => f === null);
                  if (emptyIdx !== -1) handlePlace(p, emptyIdx);
                }}
                className={`${p.color} text-white px-8 py-3 rounded-2xl shadow-lg font-bold flex items-center justify-between hover:scale-105 transition-all`}
              >
                <span>{p.name}</span>
                <i className="fas fa-plus-circle opacity-50"></i>
              </button>
            ))}
            {available.length === 0 && <p className="text-gray-400 italic">¡Todos ubicados!</p>}
          </div>
        </div>

        {feedback && (
          <div className={`mt-8 p-4 rounded-xl text-center font-bold ${feedback.includes('¡Correcto!') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-12">
          <button onClick={() => { setFloors(Array(4).fill(null)); setAvailable(PEOPLE); setFeedback(null); }} className="text-gray-500 hover:text-blue-600 font-bold">
            <i className="fas fa-undo mr-2"></i> Reiniciar
          </button>
          <div className="flex gap-4">
            <button onClick={check} className="px-6 py-2 bg-blue-500 text-white rounded-xl font-bold hover:bg-blue-600 shadow-md">
              Verificar
            </button>
            <button onClick={onNext} className="px-6 py-2 bg-purple-600 text-white rounded-xl font-bold hover:bg-purple-700 shadow-md">
              Siguiente <i className="fas fa-arrow-right ml-2"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default VerticalOrdering;

import React, { useState } from 'react';
import { Person } from '../types';

interface Props {
  onNext: () => void;
}

const PEOPLE: Person[] = [
  { id: 'a', name: 'A', color: 'bg-red-400' },
  { id: 'b', name: 'B', color: 'bg-blue-400' },
  { id: 'c', name: 'C', color: 'bg-green-400' },
  { id: 'd', name: 'D', color: 'bg-yellow-400' },
  { id: 'e', name: 'E', color: 'bg-purple-400' },
  { id: 'f', name: 'F', color: 'bg-pink-400' },
];

const CircularOrdering: React.FC<Props> = ({ onNext }) => {
  const [seats, setSeats] = useState<(Person | null)[]>(Array(6).fill(null));
  const [available, setAvailable] = useState<Person[]>(PEOPLE);
  const [feedback, setFeedback] = useState<string | null>(null);

  const toggleSeat = (idx: number) => {
    if (seats[idx]) {
      setAvailable(prev => [...prev, seats[idx]!]);
      setSeats(prev => {
        const next = [...prev];
        next[idx] = null;
        return next;
      });
    } else if (available.length > 0) {
      const person = available[0];
      setSeats(prev => {
        const next = [...prev];
        next[idx] = person;
        return next;
      });
      setAvailable(prev => prev.slice(1));
    }
  };

  const check = () => {
    // Problem Rules:
    // A se siente junto y a la derecha de B y frente a C.
    // D no se sienta junto a B.
    // E no se sienta junto a C.
    // Correct clock-wise sequence (starting A at top): A, E, D, C, F, B
    // We check for relative positioning rather than absolute index.
    const names = seats.map(s => s?.name || '');
    if (names.includes('')) {
      setFeedback("Por favor, sienta a todos los amigos.");
      return;
    }

    // This is a simplified check for the specific example logic
    const aIdx = names.indexOf('A');
    const bIdx = (aIdx + 5) % 6; // B to the left of A (A is right of B)
    const cIdx = (aIdx + 3) % 6; // C is front of A

    if (names[bIdx] === 'B' && names[cIdx] === 'C') {
       setFeedback("¡Excelente razonamiento circular! F se sienta entre B y C.");
    } else {
       setFeedback("Verifica las posiciones. 'A' debe estar a la derecha de 'B' y frente a 'C'.");
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-pink-100">
        <header className="mb-8">
          <span className="text-xs font-bold uppercase tracking-widest text-pink-400">Simulación Interactiva #3</span>
          <h2 className="text-3xl font-bold text-pink-700">Ordenamiento Circular</h2>
          <p className="text-gray-600 mt-2">
            Organiza a los amigos alrededor de la mesa circular.
          </p>
          <div className="bg-pink-50 border-l-4 border-pink-400 p-4 mt-4 text-sm italic text-gray-700">
            "Alrededor de una mesa circular se sientan 6 amigos A, B, C, D, E y F. A se sienta junto y a la derecha de B y frente a C; D no se sienta junto a B y E no se sienta junto a C. ¿Dónde se sienta F?"
          </div>
        </header>

        <div className="flex flex-col md:flex-row gap-12 items-center justify-center py-10">
          {/* Circular Table */}
          <div className="relative w-72 h-72 md:w-80 md:h-80 bg-orange-100 rounded-full border-[12px] border-orange-200 shadow-xl flex items-center justify-center">
            <div className="absolute inset-0 flex items-center justify-center">
              <span className="text-orange-300 font-extrabold text-2xl uppercase tracking-tighter">Mesa de Amigos</span>
            </div>

            {/* Seats */}
            {[0, 1, 2, 3, 4, 5].map(i => {
              const angle = i * 60 - 90; // Starting from top
              const radius = 110;
              const x = Math.cos(angle * Math.PI / 180) * radius;
              const y = Math.sin(angle * Math.PI / 180) * radius;

              return (
                <button
                  key={i}
                  onClick={() => toggleSeat(i)}
                  style={{ transform: `translate(${x}px, ${y}px)` }}
                  className={`absolute w-14 h-14 md:w-16 md:h-16 rounded-full border-4 flex items-center justify-center transition-all ${seats[i] ? `${seats[i]?.color} border-white shadow-lg text-white font-bold scale-110` : 'bg-white border-dashed border-gray-200 hover:border-pink-300'}`}
                >
                  {seats[i]?.name || ''}
                </button>
              );
            })}
          </div>

          <div className="bg-gray-50 p-6 rounded-2xl flex flex-col gap-3 min-w-[200px]">
            <h4 className="font-bold text-gray-400 text-xs mb-2">ORDEN DE LLEGADA:</h4>
            {available.map(p => (
              <div key={p.id} className={`${p.color} text-white px-4 py-2 rounded-xl font-bold shadow-sm text-center animate-pulse`}>
                Siguiente: {p.name}
              </div>
            ))}
            {available.length === 0 && <span className="text-green-500 font-bold"><i className="fas fa-check-circle"></i> Listos</span>}
            <p className="text-[10px] text-gray-400 mt-4 text-center">Haz clic en un asiento para sentar o quitar a alguien.</p>
          </div>
        </div>

        {feedback && (
          <div className={`mt-4 p-4 rounded-xl text-center font-bold ${feedback.includes('¡Excelente') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-12">
          <button onClick={() => { setSeats(Array(6).fill(null)); setAvailable(PEOPLE); setFeedback(null); }} className="text-gray-500 hover:text-pink-600 font-bold">
            <i className="fas fa-undo mr-2"></i> Reiniciar
          </button>
          <div className="flex gap-4">
            <button onClick={check} className="px-6 py-2 bg-blue-500 text-white rounded-xl font-bold hover:bg-blue-600 shadow-md">
