import React, { useState } from 'react';

interface Props {
  onNext: () => void;
}

type CellValue = 'X' | 'O' | null;

const TableOrdering: React.FC<Props> = ({ onNext }) => {
  const friends = ['Julio', 'Luis', 'Pedro', 'Manuel'];
  const games = ['Ajedrez', 'Damas', 'Ludo', 'Dominó'];

  const [grid, setGrid] = useState<CellValue[][]>(
    Array(4).fill(null).map(() => Array(4).fill(null))
  );
  const [feedback, setFeedback] = useState<string | null>(null);

  const toggleCell = (r: number, c: number) => {
    const next = [...grid];
    if (next[r][c] === null) next[r][c] = 'X';
    else if (next[r][c] === 'X') next[r][c] = 'O';
    else next[r][c] = null;
    setGrid(next);
  };

  const check = () => {
    // Correct solution based on:
    // Julio quiere ajedrez en lugar de damas -> Julio NO ajedrez (todavía no), Julio Damas (X).
    // Luis le pide fichas de Ludo a Manuel -> Manuel practica Ludo.
    // Pedro no sabe jugar dominó.
    // From manual deduction:
    // Julio: Damas
    // Manuel: Ludo
    // Pedro: Ajedrez
    // Luis: Dominó
    const solution = [
      ['O', 'X', 'O', 'O'], // Julio: Damas
      ['O', 'O', 'O', 'X'], // Luis: Dominó
      ['X', 'O', 'O', 'O'], // Pedro: Ajedrez
      ['O', 'O', 'X', 'O'], // Manuel: Ludo
    ];

    let correct = true;
    grid.forEach((row, r) => {
      row.forEach((cell, c) => {
        if (cell === 'X' && solution[r][c] !== 'X') correct = false;
        if (solution[r][c] === 'X' && cell !== 'X') correct = false;
      });
    });

    if (correct) {
      setFeedback("¡Correcto! Pedro practica ajedrez y Luis practica dominó.");
    } else {
      setFeedback("Casi... recuerda que Manuel practica Ludo y Julio prefiere Damas.");
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-green-100">
        <header className="mb-8">
          <span className="text-xs font-bold uppercase tracking-widest text-green-400">Simulación Interactiva #4</span>
          <h2 className="text-3xl font-bold text-green-700">Tabla de Doble Entrada</h2>
          <p className="text-gray-600 mt-2">
            Cruza la información para encontrar qué juego practica cada amigo.
          </p>
          <div className="bg-green-50 border-l-4 border-green-400 p-4 mt-4 text-sm italic text-gray-700">
            "Julio, Luis, Pedro y Manuel practican un juego diferente. Julio quisiera jugar ajedrez en lugar de damas. Luis le pide fichas de Ludo a Manuel. Pedro no sabe jugar dominó. ¿Quién practica ajedrez y qué juego practica Luis?"
          </div>
        </header>

        <div className="overflow-x-auto mb-10">
          <table className="w-full border-collapse">
            <thead>
              <tr>
                <th className="p-4 bg-green-100 rounded-tl-2xl border-2 border-green-200 text-green-700 font-bold">AMIGOS / JUEGOS</th>
                {games.map(g => (
                  <th key={g} className="p-4 bg-green-50 border-2 border-green-200 text-green-600">{g}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {friends.map((friend, rIdx) => (
                <tr key={friend}>
                  <td className="p-4 font-bold border-2 border-green-100 bg-gray-50">{friend}</td>
                  {games.map((game, cIdx) => (
                    <td 
                      key={game} 
                      onClick={() => toggleCell(rIdx, cIdx)}
                      className="p-4 border-2 border-green-100 text-center cursor-pointer hover:bg-green-50 transition-colors h-16 w-16"
                    >
                      {grid[rIdx][cIdx] === 'X' && <span className="text-red-500 font-black text-2xl">X</span>}
                      {grid[rIdx][cIdx] === 'O' && <span className="text-green-500 font-black text-2xl">O</span>}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="flex items-center gap-6 mb-8 text-xs text-gray-400 justify-center">
          <div className="flex items-center gap-2"><span className="w-4 h-4 bg-red-100 text-red-500 flex items-center justify-center font-bold">X</span> Sí practica</div>
          <div className="flex items-center gap-2"><span className="w-4 h-4 bg-green-100 text-green-500 flex items-center justify-center font-bold">O</span> No practica</div>
          <p>Haz clic para cambiar el estado (Vacío -> X -> O)</p>
        </div>

        {feedback && (
          <div className={`mt-4 p-4 rounded-xl text-center font-bold ${feedback.includes('¡Correcto!') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-12">
          <button onClick={() => { setGrid(Array(4).fill(null).map(() => Array(4).fill(null))); setFeedback(null); }} className="text-gray-500 hover:text-green-600 font-bold">
            <i className="fas fa-undo mr-2"></i> Reiniciar
          </button>
          <div className="flex gap-4">
            <button onClick={check} className="px-6 py-2 bg-blue-500 text-white rounded-xl font-bold hover:bg-blue-600 shadow-md">
              Verificar
            </button>
            <button onClick={onNext} className="px-6 py-2 bg-purple-600 text-white rounded-xl font-bold hover:bg-purple-700 shadow-md">
              Ir al Reto Final <i className="fas fa-star ml-2"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

