const Challenge: React.FC<Props> = ({ onRestart }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [score, setScore] = useState(0);
  const [finished, setFinished] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  const handleNext = () => {
    if (selectedOption === PROBLEMS[currentStep].answer) {
      setScore(prev => prev + 1);
    }

    if (currentStep < PROBLEMS.length - 1) {
      setCurrentStep(prev => prev + 1);
      setSelectedOption(null);
      setShowFeedback(false);
    } else {
      setFinished(true);
    }
  };

  if (finished) {
    return (
      <div className="max-w-2xl mx-auto text-center animate-fadeIn py-10">
        <div className="bg-white p-12 rounded-3xl shadow-2xl border-4 border-purple-200">
