import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  onNext: () => void;
}

type Mode = 'PAR' | 'IMPAR';

const PEOPLE_PAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'a', name: 'A', color: 'bg-blue-400' },
  { id: 'c', name: 'C', color: 'bg-green-400' },
  { id: 'f', name: 'F', color: 'bg-yellow-400' },
  { id: 'p', name: 'P', color: 'bg-purple-400' },
  { id: 'b', name: 'B', color: 'bg-pink-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const PEOPLE_IMPAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'f', name: 'F', color: 'bg-green-400' },
  { id: 'p', name: 'P', color: 'bg-blue-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-purple-400' },
];

const CircularOrdering: React.FC<Props> = ({ onNext }) => {
  const [mode, setMode] = useState<Mode>('PAR');
  const [seats, setSeats] = useState<(Person | null)[]>(Array(8).fill(null));
  const [available, setAvailable] = useState<Person[]>(PEOPLE_PAR);
  const [feedback, setFeedback] = useState<string | null>(null);

  const switchMode = (newMode: Mode) => {
    playSound('pop');
    setMode(newMode);
    setSeats(Array(newMode === 'PAR' ? 8 : 5).fill(null));
    setAvailable(newMode === 'PAR' ? PEOPLE_PAR : PEOPLE_IMPAR);
    setFeedback(null);
  };

  const toggleSeat = (idx: number) => {
    playSound('pop');
    if (seats[idx]) {
      const person = seats[idx]!;
      setAvailable(prev => [...prev, person]);
      setSeats(prev => {
        const next = [...prev];
        next[idx] = null;
        return next;
      });
    } else if (available.length > 0) {
      const person = available[0];
      setSeats(prev => {
        const next = [...prev];
        next[idx] = person;
        return next;
      });
      setAvailable(prev => prev.slice(1));
    }
  };

  const check = () => {
    const names = seats.map(s => s?.name || '');
    if (names.includes('')) {
      playSound('error');
      setFeedback("Por favor, ubica a todas las personas en la mesa.");
      return;
    }

    if (mode === 'PAR') {
      const cIdx = names.indexOf('C');
      if (cIdx === -1) { playSound('error'); setFeedback("Ubica a C como punto de referencia arriba."); return; }

      const getAt = (offset: number) => names[(cIdx + offset + 8) % 8];

      const isCorrect = 
        getAt(1) === 'F' && getAt(2) === 'P' && getAt(3) === 'B' &&
        getAt(4) === 'X' && getAt(5) === 'S' && getAt(6) === 'W' && getAt(7) === 'A';

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Excelente! Has dominado el ordenamiento con cantidad PAR. Nota cómo los que están frente a frente delimitan la derecha e izquierda.");
      } else {
        playSound('error');
        setFeedback("Revisa las posiciones: ¿Está P frente a W? ¿Está F frente a S? ¿Está S a la izquierda de X?");
      }
    } else {
      const fIdx = names.indexOf('F');
      if (fIdx === -1) { playSound('error'); setFeedback("Ubica a F como punto de referencia arriba."); return; }

      const getAt = (offset: number) => names[(fIdx + offset + 5) % 5];

      const isCorrect = 
        getAt(1) === 'P' && getAt(2) === 'X' && getAt(3) === 'S' && getAt(4) === 'W';

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Muy bien! En cantidades IMPAR no hay personas frente a frente. Se divide el resto en dos grupos iguales.");
      } else {
        playSound('error');
        setFeedback("Casi... Revisa: A la derecha de F deben estar W y S. A su izquierda P y X.");
      }
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className={`bg-white p-8 rounded-3xl shadow-xl border-4 ${mode === 'PAR' ? 'border-pink-100' : 'border-purple-100'}`}>
        <header className="mb-6">
          <div className="flex justify-between items-start">
            <div>
              <span className="text-xs font-bold uppercase tracking-widest text-pink-400">Simulación Interactiva #3</span>
              <h2 className="text-3xl font-bold text-pink-700">Ordenamiento Circular</h2>
            </div>
            <div className="flex bg-gray-100 p-1 rounded-xl">
              <button 
                onClick={() => switchMode('PAR')}
                className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${mode === 'PAR' ? 'bg-pink-500 text-white shadow-md' : 'text-gray-500 hover:bg-gray-200'}`}
              >
                Cantidad PAR (8)
              </button>
              <button 
                onClick={() => switchMode('IMPAR')}
                className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${mode === 'IMPAR' ? 'bg-purple-500 text-white shadow-md' : 'text-gray-500 hover:bg-gray-200'}`}
              >
                Cantidad IMPAR (5)
              </button>
            </div>
          </div>

          <div className="bg-gray-50 border-l-4 border-pink-400 p-4 mt-6 text-sm italic text-gray-700">
            {mode === 'PAR' ? (
              <>
                <strong>Instrucciones:</strong> Ubica a las 8 personas. 
                <ul className="list-disc list-inside mt-2">
                  <li>Frente a W está P y frente a S está F.</li>
                  <li>Junto y a la izquierda de X está S.</li>
                  <li>Adyacentes a P están B y F.</li>
                  <li>Usa a <strong>C</strong> como punto de referencia superior.</li>
                </ul>
              </>
            ) : (
              <>
                <strong>Instrucciones:</strong> Ubica a las 5 personas. 
                <ul className="list-disc list-inside mt-2">
                  <li>No existen personas sentadas frente a otra.</li>
                  <li>A la derecha de F están W y S.</li>
                  <li>A la izquierda de F están P y X.</li>
                  <li>Usa a <strong>F</strong> como punto de referencia superior.</li>
                </ul>
              </>
            )}
          </div>
        </header>

        <div className="flex flex-col md:flex-row gap-8 items-center justify-center py-6">
          {/* Table Container with relative positioning for arrows */}
          <div className="relative">
            {/* Visual Indicators for Directions */}
            <div className="absolute -top-12 left-1/2 -translate-x-1/2 flex gap-12 pointer-events-none">
              <div className="flex flex-col items-center">
                <i className="fas fa-long-arrow-alt-left text-blue-400 text-xl animate-pulse"></i>
                <span className="text-[10px] font-bold text-blue-400 uppercase">Izquierda</span>
              </div>
              <div className="flex flex-col items-center">
                <i className="fas fa-long-arrow-alt-right text-pink-400 text-xl animate-pulse"></i>
                <span className="text-[10px] font-bold text-pink-400 uppercase">Derecha</span>
              </div>
            </div>

            {/* Circular Table */}
            <div className={`relative w-72 h-72 md:w-80 md:h-80 rounded-full border-[12px] shadow-xl flex items-center justify-center ${mode === 'PAR' ? 'bg-pink-50 border-pink-100' : 'bg-purple-50 border-purple-100'}`}>
              <div className="text-center">
                <span className={`font-extrabold text-xl uppercase tracking-tighter opacity-20 ${mode === 'PAR' ? 'text-pink-300' : 'text-purple-300'}`}>
                  Mesa Redonda
                </span>
                <div className="mt-2 text-[10px] font-bold text-gray-300 italic">Simétrico</div>
              </div>

              {/* Seats */}
              {Array.from({ length: numSeats }).map((_, i) => {
                const angle = i * (360 / numSeats) - 90;
                const radius = mode === 'PAR' ? 120 : 110;
                const x = Math.cos(angle * Math.PI / 180) * radius;
                const y = Math.sin(angle * Math.PI / 180) * radius;

                return (
                  <button
                    key={i}
                    onClick={() => toggleSeat(i)}
                    style={{ transform: `translate(${x}px, ${y}px)` }}
                    className={`absolute w-12 h-12 md:w-14 md:h-14 rounded-full border-4 flex items-center justify-center transition-all ${seats[i] ? `${seats[i]?.color} border-white shadow-lg text-white font-bold scale-110` : 'bg-white border-dashed border-gray-200 hover:border-pink-300'}`}
                  >
                    {seats[i]?.name || ''}
                  </button>
                );
              })}

              {/* Opposition Lines (only for Par) */}
              {mode === 'PAR' && (
                <div className="absolute inset-0 pointer-events-none opacity-10">
                  <div className="absolute top-1/2 left-0 w-full h-0.5 bg-gray-400"></div>
                  <div className="absolute top-0 left-1/2 w-0.5 h-full bg-gray-400"></div>
                  <div className="absolute top-0 left-0 w-full h-full border-2 border-gray-400 rounded-full scale-75 rotate-45">
                    <div className="absolute top-1/2 left-0 w-full h-0.5 bg-gray-400"></div>
                    <div className="absolute top-0 left-1/2 w-0.5 h-full bg-gray-400"></div>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Sidebar Info */}
          <div className="bg-white border-2 border-gray-100 p-6 rounded-3xl flex flex-col gap-3 min-w-[220px] shadow-sm">
            <h4 className="font-bold text-gray-400 text-xs mb-2 border-b pb-2 uppercase tracking-widest">
              Por ubicar: ({available.length})
            </h4>
            <div className="grid grid-cols-2 gap-2">
              {available.map(p => (
                <div 
                  key={p.id} 
                  onClick={() => {
                    const firstEmpty = seats.indexOf(null);
                    if (firstEmpty !== -1) toggleSeat(firstEmpty);
                  }}
                  className={`${p.color} text-white p-3 rounded-xl font-bold shadow-sm text-center cursor-pointer hover:scale-105 transition-transform active:scale-95`}
                >
                  {p.name}
                </div>
              ))}
            </div>
            {available.length === 0 && (
              <div className="text-green-500 font-bold flex items-center justify-center gap-2 py-4 animate-bounce">
                <i className="fas fa-check-double"></i> ¡Mesa llena!
              </div>
            )}
            <p className="text-[10px] text-gray-400 mt-2 text-center leading-tight">
              Haz clic en la letra o en un asiento para organizar la mesa.
            </p>
          </div>
        </div>

        {feedback && (
          <div className={`mt-4 p-4 rounded-2xl text-center font-bold animate-fadeIn ${feedback.includes('¡Excelente') || feedback.includes('¡Muy bien') ? 'bg-green-100 text-green-700 border-2 border-green-200' : 'bg-red-50 text-red-600 border-2 border-red-100'}`}>
            <i className={`fas ${feedback.includes('¡') ? 'fa-star' : 'fa-lightbulb'} mr-2`}></i>
            {feedback}
          </div>
        )}

        <div className="flex flex-col md:flex-row justify-between items-center mt-10 gap-4">
          <button 
            onClick={() => { playSound('pop'); switchMode(mode); }} 
            className="text-gray-400 hover:text-pink-600 font-bold flex items-center gap-2 px-4 py-2 hover:bg-gray-50 rounded-xl transition-all"
          >
            <i className="fas fa-sync-alt"></i> Reiniciar Mesa
          </button>
          <div className="flex gap-4 w-full md:w-auto">
            <button 
              onClick={check} 
              className="flex-1 md:flex-none px-8 py-3 bg-blue-500 text-white rounded-2xl font-bold hover:bg-blue-600 shadow-lg transition-all active:scale-95"
            >
              <i className="fas fa-spell-check mr-2"></i> Verificar
            </button>
            <button 
              onClick={onNext} 
              className="flex-1 md:flex-none px-8 py-3 bg-purple-600 text-white rounded-2xl font-bold hover:bg-purple-700 shadow-lg transition-all active:scale-95"
            >
              Siguiente <i className="fas fa-chevron-right ml-2"></i>
            </button>
          </div>
        </div>
      </div>

      <div className="mt-8 bg-blue-50 p-6 rounded-3xl border border-blue-100">
        <h4 className="text-blue-700 font-bold flex items-center gap-2 mb-2">
          <i className="fas fa-book-open"></i> Recordatorio de la Guía:
        </h4>
        <p className="text-sm text-blue-600 leading-relaxed">
          {mode === 'PAR' 
            ? "En una mesa con asientos pares, siempre existe alguien sentado justo al frente. La persona frente a ti delimita lo que está a tu derecha e izquierda." 
            : "En una mesa impar, no hay nadie frente a nadie. Para saber quién está a la derecha o izquierda, divide al resto de las personas en dos grupos iguales."}
