const PROBLEMS = [
  {
    id: 1,
    question: "6 alumnos en una montaña: Arturo está más arriba que Paulo y éste entre Hugo y Fernando. Walter está más abajo que Julio y éste un lugar más abajo que Arturo. Fernando está más arriba que Walter pero un lugar más abajo que Paulo y éste más arriba que Hugo. ¿Quién está en 3er lugar?",
