  },
  {
    id: 5,
    question: "Examen de Razonamiento: A obtuvo menos que B, C menos que D, E el mismo que F, A menos que G, C el mismo que B y E más que D. ¿Quién obtuvo el menor puntaje?",
    options: ["A", "B", "F", "G"],
    answer: "A",
    explanation: "Orden: G > B = C > D > E = F > A. Por lo tanto, A es el menor."
  }
];

const Challenge: React.FC<Props> = ({ onRestart }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [score, setScore] = useState(0);
  const [finished, setFinished] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  useEffect(() => {
    if (finished) {
      playSound('finish');
    }
  }, [finished]);

  const handleVerify = () => {
    const p = PROBLEMS[currentStep];
    if (selectedOption === p.answer) {
      playSound('success');
      setScore(prev => prev + 1);
    } else {
      playSound('error');
    }
    setShowFeedback(true);
  };

  const handleNext = () => {
    playSound('pop');
    if (currentStep < PROBLEMS.length - 1) {
      setCurrentStep(prev => prev + 1);
      setSelectedOption(null);
      setShowFeedback(false);
    } else {
      setFinished(true);
    }
  };

  if (finished) {
    return (
      <div className="max-w-2xl mx-auto text-center animate-fadeIn py-10">
        <div className="bg-white p-12 rounded-3xl shadow-2xl border-4 border-purple-200">
          <div className="w-24 h-24 bg-purple-100 rounded-full flex items-center justify-center mx-auto mb-6">
            <i className={`fas ${score >= 3 ? 'fa-trophy text-yellow-500' : 'fa-graduation-cap text-purple-500'} text-5xl`}></i>
          </div>
          <h2 className="text-4xl font-bold text-gray-800 mb-4">¡Reto Completado!</h2>
          <p className="text-xl text-gray-600 mb-8">
            Tu puntaje final es: <span className="text-purple-600 font-extrabold">{score} / {PROBLEMS.length}</span>
          </p>
          <div className="flex flex-col gap-4">
            <button 
              onClick={() => { playSound('pop'); onRestart(); }}
              className="bg-purple-600 text-white px-8 py-3 rounded-2xl font-bold hover:bg-purple-700 transition-all shadow-lg"
            >
              Volver al Inicio
            </button>
          </div>
        </div>
      </div>
    );
  }

  const p = PROBLEMS[currentStep];

  return (
    <div className="max-w-3xl mx-auto animate-slideIn">
      <div className="bg-white rounded-3xl overflow-hidden shadow-xl border border-gray-100">
        <div className="bg-gradient-to-r from-purple-600 to-blue-500 p-6 text-white flex justify-between items-center">
          <div>
            <span className="text-xs uppercase font-bold opacity-75">Problema {currentStep + 1} de {PROBLEMS.length}</span>
            <h3 className="text-xl font-bold">Poniendo a Prueba tu Lógica</h3>
          </div>
          <div className="text-2xl font-black">{Math.round(((currentStep)/PROBLEMS.length)*100)}%</div>
        </div>

        <div className="p-8">
          <p className="text-lg text-gray-700 leading-relaxed mb-8 bg-gray-50 p-6 rounded-2xl italic border-l-8 border-purple-500">
            "{p.question}"
          </p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {p.options.map(opt => (
              <button
                key={opt}
                onClick={() => { 
                  if (!showFeedback) {
                    playSound('pop');
                    setSelectedOption(opt); 
                  }
                }}
                className={`p-4 rounded-xl border-2 text-left font-bold transition-all ${
                  selectedOption === opt 
                    ? 'border-purple-600 bg-purple-50 text-purple-700 shadow-md scale-[1.02]' 
                    : 'border-gray-100 hover:border-blue-200 hover:bg-blue-50 text-gray-600'
                } ${showFeedback ? 'cursor-default' : 'cursor-pointer'}`}
              >
                {opt}
              </button>
            ))}
          </div>

          {showFeedback && (
            <div className={`mt-8 p-4 rounded-xl ${selectedOption === p.answer ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
              <div className="font-bold flex items-center gap-2 mb-1">
                <i className={`fas ${selectedOption === p.answer ? 'fa-check-circle' : 'fa-times-circle'}`}></i>
                {selectedOption === p.answer ? '¡Muy bien!' : 'No exactamente.'}
              </div>
              <p className="text-sm opacity-90">{p.explanation}</p>
            </div>
          )}

          <div className="mt-10 flex justify-end">
            {!showFeedback ? (
              <button 
                disabled={!selectedOption}
                onClick={handleVerify}
                className={`px-10 py-3 rounded-2xl font-bold transition-all shadow-lg ${selectedOption ? 'bg-blue-500 text-white hover:bg-blue-600' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
              >
                Verificar Respuesta
              </button>
            ) : (
              <button 
                onClick={handleNext}
                className="bg-purple-600 text-white px-10 py-3 rounded-2xl font-bold hover:bg-purple-700 transition-all shadow-lg flex items-center gap-2"
              >
                {currentStep === PROBLEMS.length - 1 ? 'Finalizar' : 'Siguiente'} <i className="fas fa-arrow-right"></i>
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Challenge;

