import React, { useState } from 'react';
import { View, Person } from './types';
import Welcome from './components/Welcome';
import Theory from './components/Theory';
import HorizontalOrdering from './components/HorizontalOrdering';
import VerticalOrdering from './components/VerticalOrdering';
import CircularOrdering from './components/CircularOrdering';
import TableOrdering from './components/TableOrdering';
import Challenge from './components/Challenge';
import Footer from './components/Footer';

// Initial states for simulations
const INITIAL_HORIZONTAL: Person[] = [
  { id: '1', name: 'María', color: 'bg-red-400' },
  { id: '2', name: 'Juana', color: 'bg-blue-400' },
  { id: '3', name: 'Ana', color: 'bg-green-400' },
  { id: '4', name: 'Inés', color: 'bg-yellow-400' },
  { id: '5', name: 'Enma', color: 'bg-pink-400' },
];

const INITIAL_VERTICAL: Person[] = [
  { id: 'p1', name: 'Raúl', color: 'bg-orange-400' },
  { id: 'p2', name: 'Pedro', color: 'bg-indigo-400' },
  { id: 'p3', name: 'Carlos', color: 'bg-emerald-400' },
  { id: 'p4', name: 'Julio', color: 'bg-rose-400' },
];

const PEOPLE_PAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'a', name: 'A', color: 'bg-blue-400' },
  { id: 'c', name: 'C', color: 'bg-green-400' },
  { id: 'f', name: 'F', color: 'bg-yellow-400' },
  { id: 'p', name: 'P', color: 'bg-purple-400' },
  { id: 'b', name: 'B', color: 'bg-pink-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.WELCOME);

  // Simulation States (Lifting state to persist answers)
  const [hSlots, setHSlots] = useState<(Person | null)[]>(Array(5).fill(null));
  const [hAvailable, setHAvailable] = useState<Person[]>(INITIAL_HORIZONTAL);

  const [vFloors, setVFloors] = useState<(Person | null)[]>(Array(4).fill(null));
  const [vAvailable, setVAvailable] = useState<Person[]>(INITIAL_VERTICAL);

  const [cMode, setCMode] = useState<'PAR' | 'IMPAR'>('PAR');
  const [cSeats, setCSeats] = useState<(Person | null)[]>(Array(8).fill(null));
  const [cAvailable, setCAvailable] = useState<Person[]>(PEOPLE_PAR);

  const [tGrid, setTGrid] = useState<(string | null)[][]>(Array(4).fill(null).map(() => Array(4).fill(null)));

  const renderView = () => {
    switch (currentView) {
      case View.WELCOME:
        return <Welcome onStart={() => setCurrentView(View.THEORY)} />;
      case View.THEORY:
        return <Theory onNext={() => setCurrentView(View.HORIZONTAL)} />;
      case View.HORIZONTAL:
        return (
          <HorizontalOrdering 
            slots={hSlots} setSlots={setHSlots}
            available={hAvailable} setAvailable={setHAvailable}
            onNext={() => setCurrentView(View.VERTICAL)} 
            onBack={() => setCurrentView(View.THEORY)}
          />
        );
      case View.VERTICAL:
        return (
          <VerticalOrdering 
            floors={vFloors} setFloors={setVFloors}
            available={vAvailable} setAvailable={setVAvailable}
            onNext={() => setCurrentView(View.CIRCULAR)} 
            onBack={() => setCurrentView(View.HORIZONTAL)}
          />
        );
      case View.CIRCULAR:
        return (
          <CircularOrdering 
            mode={cMode} setMode={setCMode}
            seats={cSeats} setSeats={setCSeats}
            available={cAvailable} setAvailable={setCAvailable}
            onNext={() => setCurrentView(View.TABLE)} 
            onBack={() => setCurrentView(View.VERTICAL)}
          />
        );
      case View.TABLE:
        return (
          <TableOrdering 
            grid={tGrid} setGrid={setTGrid}
            onNext={() => setCurrentView(View.CHALLENGE)} 
            onBack={() => setCurrentView(View.CIRCULAR)}
          />
        );
      case View.CHALLENGE:
        return <Challenge onRestart={() => setCurrentView(View.WELCOME)} onBack={() => setCurrentView(View.TABLE)} />;
      default:
        return <Welcome onStart={() => setCurrentView(View.THEORY)} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      <div className="absolute inset-0 bg-pattern -z-10"></div>

      {currentView !== View.WELCOME && (
        <header className="bg-white/80 backdrop-blur-md sticky top-0 z-50 shadow-sm border-b border-purple-100">
          <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
            <button 
              onClick={() => setCurrentView(View.WELCOME)}
              className="flex items-center gap-2 text-purple-600 font-bold text-xl"
            >
              <i className="fas fa-brain"></i>
              <span>Lógica <span className="text-blue-500">7°</span></span>
            </button>
            <nav className="hidden md:flex gap-4">
              {[
                { label: 'Teoría', view: View.THEORY },
                { label: 'Horizontal', view: View.HORIZONTAL },
                { label: 'Vertical', view: View.VERTICAL },
                { label: 'Circular', view: View.CIRCULAR },
                { label: 'Tablas', view: View.TABLE },
                { label: 'Reto Final', view: View.CHALLENGE },
              ].map((item) => (
                <button
                  key={item.view}
                  onClick={() => setCurrentView(item.view)}
                  className={`px-3 py-1 rounded-full text-sm font-medium transition-all ${
                    currentView === item.view 
                      ? 'bg-purple-600 text-white' 
                      : 'text-gray-600 hover:bg-purple-50'
                  }`}
                >
                  {item.label}
                </button>
              ))}
            </nav>
          </div>
        </header>
      )}

      <main className="flex-grow container mx-auto px-4 py-8">
        {renderView()}
      </main>

      <Footer />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  slots: (Person | null)[];
  setSlots: React.Dispatch<React.SetStateAction<(Person | null)[]>>;
  available: Person[];
  setAvailable: React.Dispatch<React.SetStateAction<Person[]>>;
  onNext: () => void;
  onBack: () => void;
}

const INITIAL_PEOPLE: Person[] = [
  { id: '1', name: 'María', color: 'bg-red-400' },
  { id: '2', name: 'Juana', color: 'bg-blue-400' },
  { id: '3', name: 'Ana', color: 'bg-green-400' },
  { id: '4', name: 'Inés', color: 'bg-yellow-400' },
  { id: '5', name: 'Enma', color: 'bg-pink-400' },
];

const HorizontalOrdering: React.FC<Props> = ({ slots, setSlots, available, setAvailable, onNext, onBack }) => {
  const [feedback, setFeedback] = useState<string | null>(null);

  const handlePlace = (person: Person, index: number) => {
    playSound('pop');
    const newSlots = [...slots];
    const oldPerson = newSlots[index];

    newSlots[index] = person;
    setSlots(newSlots);

    setAvailable(prev => {
      const filtered = prev.filter(p => p.id !== person.id);
      if (oldPerson) return [...filtered, oldPerson];
      return filtered;
    });
  };

  const handleRemove = (index: number) => {
    const s = slots[index];
    if (s) {
      playSound('pop');
      setSlots(prev => {
        const next = [...prev];
        next[index] = null;
        return next;
      });
      setAvailable(prev => [...prev, s]);
    }
  };

  const reset = () => {
    playSound('pop');
    setSlots(Array(5).fill(null));
    setAvailable(INITIAL_PEOPLE);
    setFeedback(null);
  };

  const check = () => {
    const correctNames = ['Inés', 'Enma', 'Ana', 'Juana', 'María'];
    const currentNames = slots.map(s => s?.name);

    if (currentNames.every((name, i) => name === correctNames[i])) {
      playSound('success');
      setFeedback("¡Excelente! Has ordenado correctamente de menor a mayor.");
    } else {
      playSound('error');
      setFeedback("Casi lo tienes. Revisa los datos: 'María es la mayor de todas' e 'Inés es la más joven'.");
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-purple-100">
        <header className="mb-8">
          <span className="text-xs font-bold uppercase tracking-widest text-purple-400">Simulación Interactiva #1</span>
          <h2 className="text-3xl font-bold text-purple-700">Ordenamiento Horizontal</h2>
          <p className="text-gray-600 mt-2">
            <strong>Reto:</strong> Ordena de <strong>Menor (Izquierda)</strong> a <strong>Mayor (Derecha)</strong> de edad.
          </p>
          <div className="bg-purple-50 border-l-4 border-purple-400 p-4 mt-4 text-sm italic text-gray-700">
            "María es mucho mayor que Juana. Ana es más joven que Juana pero mucho mayor que Inés e Inés es más joven que Enma."
          </div>
        </header>

        <div className="flex flex-wrap gap-4 justify-center mb-12 min-h-[80px]">
          {available.map(p => (
            <button
              key={p.id}
              onClick={() => {
                const emptyIdx = slots.findIndex(s => s === null);
                if (emptyIdx !== -1) handlePlace(p, emptyIdx);
              }}
              className={`${p.color} text-white px-6 py-3 rounded-2xl shadow-md font-bold hover:scale-105 transition-transform`}
            >
              {p.name}
            </button>
          ))}
        </div>

        <div className="relative mb-12">
          <div className="h-2 bg-gray-200 w-full rounded-full absolute top-1/2 -translate-y-1/2"></div>
          <div className="flex justify-between relative z-10 px-4">
            {slots.map((s, i) => (
              <div key={i} className="flex flex-col items-center">
                <div 
                  onClick={() => handleRemove(i)}
                  className={`w-16 h-16 md:w-20 md:h-20 rounded-full border-4 border-dashed border-purple-200 flex items-center justify-center cursor-pointer transition-all ${s ? 'border-solid border-purple-500 scale-110' : 'hover:border-purple-300'}`}
                >
                  {s ? (
                    <div className={`${s.color} w-full h-full rounded-full flex items-center justify-center text-white font-bold text-xs md:text-sm`}>
                      {s.name}
                    </div>
                  ) : (
                    <span className="text-gray-300 text-xs">Pos. {i+1}</span>
                  )}
                </div>
                <span className="mt-2 text-[10px] uppercase font-bold text-gray-400">
                  {i === 0 ? 'Más Joven' : i === 4 ? 'Más Mayor' : ''}
                </span>
              </div>
            ))}
          </div>
        </div>

        {feedback && (
          <div className={`p-4 rounded-xl mb-6 text-center font-bold ${feedback.includes('Excelente') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center">
          <button onClick={reset} className="text-gray-500 hover:text-purple-600 font-bold transition-colors">
            <i className="fas fa-undo mr-2"></i> Reiniciar
          </button>
          <div className="flex gap-4">
            <button onClick={() => { playSound('pop'); onBack(); }} className="px-6 py-2 border-2 border-gray-200 text-gray-500 rounded-xl font-bold hover:bg-gray-50 transition-colors">
              Regresar
            </button>
            <button onClick={check} className="px-6 py-2 bg-blue-500 text-white rounded-xl font-bold hover:bg-blue-600 shadow-md">
              Verificar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="px-6 py-2 bg-purple-600 text-white rounded-xl font-bold hover:bg-purple-700 shadow-md">
              Siguiente <i className="fas fa-arrow-right ml-2"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HorizontalOrdering;

