    const newFloors = [...floors];
    const oldPerson = newFloors[floorIdx];
    newFloors[floorIdx] = person;
    setFloors(newFloors);
    setAvailable(prev => {
      const filtered = prev.filter(p => p.id !== person.id);
      if (oldPerson) return [...filtered, oldPerson];
      return filtered;
    });
  };

  const handleRemove = (idx: number) => {
    if (floors[idx]) {
      playSound('pop');
      setAvailable(prev => [...prev, floors[idx]!]);
      setFloors(prev => {
        const next = [...prev];
        next[idx] = null;
        return next;
      });
    }
  };

  const check = () => {
    const correctNames = ['Raúl', 'Pedro', 'Julio', 'Carlos'];
    const currentNames = floors.map(f => f?.name);

    if (currentNames.every((name, i) => name === correctNames[i])) {
      playSound('success');
      setFeedback("¡Correcto! Julio vive en el 3er piso.");
    } else {
      playSound('error');
      setFeedback("Revisa bien: Raúl va en el primero, y Julio vive justo arriba de Pedro.");
    }
  };

  const reset = () => {
    playSound('pop');
    setFloors(Array(4).fill(null)); 
    setAvailable(INITIAL_VERTICAL); 
    setFeedback(null);
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-blue-100">
        <header className="mb-8">
          <span className="text-xs font-bold uppercase tracking-widest text-blue-400">Simulación Interactiva #2</span>
          <h2 className="text-3xl font-bold text-blue-700">Ordenamiento Vertical</h2>
          <p className="text-gray-600 mt-2">
            Ubica a los amigos en sus pisos correspondientes.
          </p>
          <div className="bg-blue-50 border-l-4 border-blue-400 p-4 mt-4 text-sm italic text-gray-700">
            "Los primos viven en un edificio de 4 pisos. Raúl vive en el primer piso. Pedro vive más abajo que Carlos y Julio vive un piso más arriba que Pedro. ¿Quién vive en el 3er piso?"
          </div>
        </header>

        <div className="flex flex-col md:flex-row gap-12 items-center justify-center">
          <div className="w-full md:w-64 bg-gray-100 p-4 rounded-3xl border-8 border-gray-200 shadow-inner">
            {[3, 2, 1, 0].map(idx => (
              <div 
                key={idx} 
                onClick={() => handleRemove(idx)}
                className={`h-24 mb-2 last:mb-0 rounded-xl border-2 border-dashed flex items-center justify-center cursor-pointer transition-all ${floors[idx] ? 'bg-white border-blue-400 shadow-md' : 'border-gray-300 hover:border-blue-300'}`}
              >
                {floors[idx] ? (
                  <div className={`flex items-center gap-3 ${floors[idx]?.color} text-white px-4 py-2 rounded-lg font-bold w-full mx-2 justify-center`}>
                    <i className="fas fa-user"></i>
                    {floors[idx]?.name}
                  </div>
                ) : (
                  <span className="text-gray-300 font-bold">Piso {idx + 1}</span>
                )}
              </div>
            ))}
            <div className="h-4 bg-gray-400 rounded-full mt-4 w-1/2 mx-auto"></div>
          </div>

          <div className="flex flex-col gap-4">
            <h4 className="font-bold text-gray-500 uppercase text-xs tracking-widest">Amigos por ubicar:</h4>
            {available.map(p => (
              <button
                key={p.id}
                onClick={() => {
                  const emptyIdx = floors.findIndex(f => f === null);
                  if (emptyIdx !== -1) handlePlace(p, emptyIdx);
                }}
                className={`${p.color} text-white px-8 py-3 rounded-2xl shadow-lg font-bold flex items-center justify-between hover:scale-105 transition-all`}
              >
                <span>{p.name}</span>
                <i className="fas fa-plus-circle opacity-50"></i>
              </button>
            ))}
            {available.length === 0 && <p className="text-gray-400 italic">¡Todos ubicados!</p>}
          </div>
        </div>

        {feedback && (
          <div className={`mt-8 p-4 rounded-xl text-center font-bold ${feedback.includes('¡Correcto!') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-12">
          <button onClick={reset} className="text-gray-500 hover:text-blue-600 font-bold">
            <i className="fas fa-undo mr-2"></i> Reiniciar
          </button>
          <div className="flex gap-4">
            <button onClick={() => { playSound('pop'); onBack(); }} className="px-6 py-2 border-2 border-gray-200 text-gray-500 rounded-xl font-bold hover:bg-gray-50 transition-colors">
              Regresar
            </button>
            <button onClick={check} className="px-6 py-2 bg-blue-500 text-white rounded-xl font-bold hover:bg-blue-600 shadow-md">
              Verificar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="px-6 py-2 bg-purple-600 text-white rounded-xl font-bold hover:bg-purple-700 shadow-md">
              Siguiente <i className="fas fa-arrow-right ml-2"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

