          <div className="mt-10 flex justify-end gap-4">
            {!showFeedback ? (
              <>
                 <button onClick={() => { playSound('pop'); onBack(); }} className="px-10 py-3 border-2 border-gray-200 text-gray-500 rounded-2xl font-bold hover:bg-gray-50">
