import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  mode: 'PAR' | 'IMPAR';
  setMode: React.Dispatch<React.SetStateAction<'PAR' | 'IMPAR'>>;
  seats: (Person | null)[];
  setSeats: React.Dispatch<React.SetStateAction<(Person | null)[]>>;
  available: Person[];
  setAvailable: React.Dispatch<React.SetStateAction<Person[]>>;
  onNext: () => void;
  onBack: () => void;
}

const PEOPLE_PAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'a', name: 'A', color: 'bg-blue-400' },
  { id: 'c', name: 'C', color: 'bg-green-400' },
  { id: 'f', name: 'F', color: 'bg-yellow-400' },
  { id: 'p', name: 'P', color: 'bg-purple-400' },
  { id: 'b', name: 'B', color: 'bg-pink-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const PEOPLE_IMPAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'f', name: 'F', color: 'bg-green-400' },
  { id: 'p', name: 'P', color: 'bg-blue-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const CircularOrdering: React.FC<Props> = ({ mode, setMode, seats, setSeats, available, setAvailable, onNext, onBack }) => {
  const [feedback, setFeedback] = useState<string | null>(null);
  const numSeats = mode === 'PAR' ? 8 : 5;

  const switchMode = (newMode: 'PAR' | 'IMPAR') => {
    playSound('pop');
    setMode(newMode);
    setSeats(Array(newMode === 'PAR' ? 8 : 5).fill(null));
    setAvailable(newMode === 'PAR' ? PEOPLE_PAR : PEOPLE_IMPAR);
    setFeedback(null);
  };

  const toggleSeat = (idx: number) => {
    playSound('pop');
    if (seats[idx]) {
      const person = seats[idx]!;
      setAvailable(prev => [...prev, person]);
      setSeats(prev => {
        const next = [...prev];
        next[idx] = null;
        return next;
      });
    } else if (available.length > 0) {
      const person = available[0];
      setSeats(prev => {
        const next = [...prev];
        next[idx] = person;
        return next;
      });
      setAvailable(prev => prev.slice(1));
    }
  };

  const check = () => {
    const names = seats.map(s => s?.name || '');
    if (names.includes('')) {
      playSound('error');
      setFeedback("Por favor, ubica a todas las personas en la mesa.");
      return;
    }

    if (mode === 'PAR') {
      const cIdx = names.indexOf('C');
      if (cIdx === -1) { playSound('error'); setFeedback("Ubica a C como punto de referencia arriba."); return; }
      const getAt = (offset: number) => names[(cIdx + offset + 8) % 8];

      // Lógica: W frente a P, S frente a F, S a la izq de X, P entre B y F.
      const isCorrect = 
        getAt(4) === 'X' && // X frente a C
        getAt(5) === 'S' && // S a la izq de X
        getAt(1) === 'F' && // F frente a S (offset 4 desde S)
        getAt(2) === 'P' && // P adyacente a F
        getAt(3) === 'B' && // P entre B y F
        getAt(6) === 'W';   // W frente a P

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Excelente! Has dominado el ordenamiento circular PAR.");
      } else {
        playSound('error');
        setFeedback("Revisa: W debe estar frente a P, y S junto a la izquierda de X.");
      }
    } else {
      const fIdx = names.indexOf('F');
      if (fIdx === -1) { playSound('error'); setFeedback("Ubica a F como punto de referencia arriba."); return; }
      const getAt = (offset: number) => names[(fIdx + offset + 5) % 5];

      // Regla IMPAR: F arriba. Der: W, S. Izq: P, X.
      const der = [getAt(1), getAt(2)];
      const izq = [getAt(3), getAt(4)];

      const isCorrect = 
        der.includes('W') && der.includes('S') && 
        izq.includes('P') && izq.includes('X');

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Muy bien! En la mesa impar dividiste bien los grupos laterales.");
      } else {
        playSound('error');
        setFeedback("Casi... a la derecha de F deben estar W y S.");
      }
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className={`bg-white p-6 md:p-8 rounded-3xl shadow-xl border-4 ${mode === 'PAR' ? 'border-pink-100' : 'border-purple-100'}`}>
        <header className="mb-6">
          <div className="flex justify-between items-center mb-4">
            <div>
              <span className="text-[10px] font-bold uppercase tracking-widest text-pink-400">Interactiva #3</span>
              <h2 className="text-2xl md:text-3xl font-bold text-pink-700">Mesa Circular</h2>
            </div>
            <div className="flex bg-gray-100 p-1 rounded-xl shrink-0">
              <button 
                onClick={() => switchMode('PAR')}
                className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all ${mode === 'PAR' ? 'bg-pink-500 text-white shadow-md' : 'text-gray-500'}`}
              >
                PAR (8)
              </button>
              <button 
                onClick={() => switchMode('IMPAR')}
                className={`px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all ${mode === 'IMPAR' ? 'bg-purple-500 text-white shadow-md' : 'text-gray-500'}`}
              >
                IMPAR (5)
              </button>
            </div>
          </div>

          <div className="bg-pink-50 border-l-4 border-pink-400 p-4 text-sm text-gray-700 rounded-r-xl">
            <h4 className="font-bold mb-1 text-pink-800"><i className="fas fa-list-check mr-2"></i>Condiciones del reto:</h4>
            {mode === 'PAR' ? (
              <ul className="list-disc list-inside space-y-0.5 text-xs">
                <li>Usa a <strong>C</strong> como referencia en el asiento superior.</li>
                <li><strong>W</strong> se sienta frente a <strong>P</strong>.</li>
                <li><strong>S</strong> se sienta frente a <strong>F</strong>.</li>
                <li><strong>S</strong> está junto y a la izquierda de <strong>X</strong>.</li>
                <li><strong>P</strong> está entre <strong>B</strong> y <strong>F</strong>.</li>
              </ul>
            ) : (
              <ul className="list-disc list-inside space-y-0.5 text-xs">
                <li>Usa a <strong>F</strong> como referencia en el asiento superior.</li>
                <li>A la <strong>derecha</strong> de F se sientan W y S.</li>
                <li>A la <strong>izquierda</strong> de F se sientan P y X.</li>
              </ul>
            )}
          </div>
        </header>

        <div className="flex flex-col lg:flex-row gap-8 items-center justify-center py-4">
          <div className="relative">
             {/* Indicadores de dirección */}
            <div className="absolute -top-10 left-0 right-0 flex justify-between px-10 pointer-events-none opacity-50">
               <div className="flex flex-col items-center"><i className="fas fa-arrow-rotate-left text-blue-400"></i><span className="text-[8px] font-bold">IZQUIERDA</span></div>
               <div className="flex flex-col items-center"><i className="fas fa-arrow-rotate-right text-pink-400"></i><span className="text-[8px] font-bold">DERECHA</span></div>
            </div>

            <div className={`relative w-64 h-64 md:w-80 md:h-80 rounded-full border-[10px] shadow-xl flex items-center justify-center ${mode === 'PAR' ? 'bg-pink-50 border-pink-100' : 'bg-purple-50 border-purple-100'}`}>
              <div className="text-center opacity-20 select-none">
                <span className="font-extrabold text-lg uppercase tracking-widest">Mesa</span>
              </div>
              {Array.from({ length: numSeats }).map((_, i) => {
                const angle = i * (360 / numSeats) - 90;
                const radius = mode === 'PAR' ? 115 : 105;
                const x = Math.cos(angle * Math.PI / 180) * radius;
                const y = Math.sin(angle * Math.PI / 180) * radius;

                return (
                  <div 
                    key={i}
                    onClick={() => toggleSeat(i)}
                    className="absolute w-12 h-12 md:w-16 md:h-16 flex items-center justify-center cursor-pointer transform -translate-x-1/2 -translate-y-1/2"
                    style={{ left: `calc(50% + ${x}px)`, top: `calc(50% + ${y}px)` }}
                  >
                    <div className={`w-full h-full rounded-full border-2 border-dashed flex items-center justify-center transition-all ${seats[i] ? 'border-solid border-pink-500 bg-white scale-110 shadow-md' : 'border-gray-300 hover:border-pink-300'}`}>
                      {seats[i] ? (
                        <div className={`${seats[i]?.color} w-full h-full rounded-full flex items-center justify-center text-white font-bold text-xs`}>
                          {seats[i]?.name}
                        </div>
                      ) : (
                        <span className="text-[8px] text-gray-400 font-bold">{i + 1}</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="flex flex-col gap-3">
             <h4 className="font-bold text-gray-500 uppercase text-[10px] tracking-widest text-center">Disponibles:</h4>
             <div className="flex flex-wrap lg:flex-col gap-2 justify-center">
               {available.map(p => (
                 <div
                   key={p.id}
                   className={`${p.color} text-white px-4 py-2 rounded-xl shadow-sm font-bold text-xs flex items-center justify-between min-w-[100px]`}
                 >
                   <span>{p.name}</span>
                   <i className="fas fa-hand-pointer opacity-30 text-[10px]"></i>
                 </div>
               ))}
               {available.length === 0 && <p className="text-gray-400 italic text-[10px] text-center">Ubicados</p>}
             </div>
          </div>
        </div>

        {feedback && (
          <div className={`mt-6 p-4 rounded-xl text-center font-bold text-sm ${feedback.includes('¡Excelente!') || feedback.includes('¡Muy bien!') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-10">
          <button 
            onClick={() => {
              playSound('pop');
              setSeats(Array(numSeats).fill(null));
              setAvailable(mode === 'PAR' ? PEOPLE_PAR : PEOPLE_IMPAR);
              setFeedback(null);
            }} 
            className="text-gray-400 hover:text-pink-600 font-bold text-xs transition-colors"
          >
            <i className="fas fa-undo mr-1"></i> Reiniciar
          </button>
          <div className="flex gap-3">
            <button onClick={() => { playSound('pop'); onBack(); }} className="px-4 py-1.5 border-2 border-gray-100 text-gray-400 rounded-lg font-bold text-xs hover:bg-gray-50">
              Regresar
            </button>
            <button onClick={check} className="px-4 py-1.5 bg-blue-500 text-white rounded-lg font-bold text-xs hover:bg-blue-600 shadow-sm">
              Verificar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="px-4 py-1.5 bg-purple-600 text-white rounded-lg font-bold text-xs hover:bg-purple-700 shadow-sm">
              Siguiente <i className="fas fa-arrow-right ml-1"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

