                key={idx} 
                onClick={() => handleRemove(idx)}
                className={`h-16 mb-2 last:mb-0 rounded-xl border-2 border-dashed flex items-center justify-center cursor-pointer transition-all ${floors[idx] ? 'bg-white border-blue-400 shadow-sm' : 'border-gray-300 hover:border-blue-200'}`}
              >
                {floors[idx] ? (
                  <div className={`flex items-center gap-2 ${floors[idx]?.color} text-white px-3 py-1.5 rounded-lg font-bold text-xs w-full mx-1 justify-center`}>
                    {floors[idx]?.name}
                  </div>
                ) : (
                  <span className="text-gray-300 font-bold text-[10px]">Piso {idx + 1}</span>
                )}
              </div>
            ))}
          </div>

          <div className="flex flex-wrap md:flex-col gap-2 justify-center">
            {available.map(p => (
              <button
                key={p.id}
                onClick={() => {
                  const emptyIdx = floors.findIndex(f => f === null);
                  if (emptyIdx !== -1) handlePlace(p, emptyIdx);
                }}
                className={`${p.color} text-white px-4 py-2 rounded-xl shadow-md font-bold text-xs flex items-center gap-2 hover:scale-105 transition-all`}
              >
                <span>{p.name}</span>
                <i className="fas fa-plus-circle opacity-50 text-[10px]"></i>
              </button>
            ))}
          </div>
        </div>

        {feedback && (
          <div className={`mt-6 p-3 rounded-xl text-center text-xs font-bold ${feedback.includes('¡Correcto!') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-8 border-t pt-6">
          <button onClick={reset} className="text-gray-400 hover:text-blue-600 font-bold text-xs">
            <i className="fas fa-sync-alt"></i>
          </button>
          <div className="flex gap-2">
            <button onClick={() => { playSound('pop'); onBack(); }} className="w-10 h-10 flex items-center justify-center border-2 border-gray-100 text-gray-400 rounded-xl hover:bg-gray-50 transition-all">
              <i className="fas fa-chevron-left"></i>
            </button>
            <button onClick={check} className="px-4 py-2 bg-blue-500 text-white rounded-xl font-bold text-xs hover:bg-blue-600 shadow-md">
              Verificar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="w-10 h-10 flex items-center justify-center bg-purple-600 text-white rounded-xl hover:bg-purple-700 shadow-md transition-all">
              <i className="fas fa-chevron-right"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

