import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  mode: 'PAR' | 'IMPAR';
  setMode: React.Dispatch<React.SetStateAction<'PAR' | 'IMPAR'>>;
  seats: (Person | null)[];
  setSeats: React.Dispatch<React.SetStateAction<(Person | null)[]>>;
  available: Person[];
  setAvailable: React.Dispatch<React.SetStateAction<Person[]>>;
  onNext: () => void;
  onBack: () => void;
}

const PEOPLE_PAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'a', name: 'A', color: 'bg-blue-400' },
  { id: 'c', name: 'C', color: 'bg-green-400' },
  { id: 'f', name: 'F', color: 'bg-yellow-400' },
  { id: 'p', name: 'P', color: 'bg-purple-400' },
  { id: 'b', name: 'B', color: 'bg-pink-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const PEOPLE_IMPAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'f', name: 'F', color: 'bg-green-400' },
  { id: 'p', name: 'P', color: 'bg-blue-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const CircularOrdering: React.FC<Props> = ({ mode, setMode, seats, setSeats, available, setAvailable, onNext, onBack }) => {
  const [feedback, setFeedback] = useState<string | null>(null);
  const numSeats = mode === 'PAR' ? 8 : 5;

  const switchMode = (newMode: 'PAR' | 'IMPAR') => {
    playSound('pop');
    setMode(newMode);
    setSeats(Array(newMode === 'PAR' ? 8 : 5).fill(null));
    setAvailable(newMode === 'PAR' ? PEOPLE_PAR : PEOPLE_IMPAR);
    setFeedback(null);
  };

  const toggleSeat = (idx: number) => {
    playSound('pop');
    if (seats[idx]) {
      const person = seats[idx]!;
      setAvailable(prev => [...prev, person]);
      setSeats(prev => {
        const next = [...prev];
        next[idx] = null;
        return next;
      });
    } else if (available.length > 0) {
      const person = available[0];
      setSeats(prev => {
        const next = [...prev];
        next[idx] = person;
        return next;
      });
      setAvailable(prev => prev.slice(1));
    }
  };

  const check = () => {
    const names = seats.map(s => s?.name || '');
    if (names.includes('')) {
      playSound('error');
      setFeedback("Por favor, ubica a todas las personas en la mesa.");
      return;
    }

    // Perspectiva del espectador (Espejo): 
    // Superior = 0
    // Lado Derecho (Sentido Horario) = 1, 2, 3...
    // Lado Izquierdo (Sentido Anti-horario) = 7, 6, 5...

    if (mode === 'PAR') {
      const cIdx = names.indexOf('C');
      if (cIdx !== 0) { playSound('error'); setFeedback("Coloca a C en el asiento superior (1) primero."); return; }

      const getAt = (idx: number) => names[idx];

      // Reglas: W frente a P, S frente a F, S a la izq de X, P entre B y F.
      // Un orden válido: 0:C, 1:A, 2:B, 3:P, 4:W, 5:F, 6:S, 7:X
      // Izq de X (Anti-horario desde X en 7) es 6: S. Correcto.
      // P (3) frente a X (7)? No, frente es +4.
      // Vamos a definir una solución clara:
      // 0:C, 4:X (Frente), 5:S (Izq de X), 1:F (Frente a S), 2:P (Junto F), 3:B (Junto P), 6:W (Frente P), 7:A (Restante)

      const isCorrect = 
        getAt(4) === 'X' && 
        getAt(5) === 'S' && // Izquierda visual de X (Anti-horario)
        getAt(1) === 'F' && // Frente a S
        getAt(2) === 'P' && // Junto a F
        getAt(6) === 'W';   // Frente a P (2+4=6)

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Excelente! Has resuelto la lógica circular PAR.");
      } else {
        playSound('error');
        setFeedback("Revisa: S debe estar a la izquierda de X, y W frente a P.");
      }
    } else {
      const fIdx = names.indexOf('F');
      if (fIdx !== 0) { playSound('error'); setFeedback("Coloca a F en el asiento superior primero."); return; }

      // Lado Derecho visual: 1, 2. Lado Izquierdo visual: 4, 3.
      const der = [names[1], names[2]];
      const izq = [names[3], names[4]];

      const isCorrect = 
        der.includes('W') && der.includes('S') && 
        izq.includes('P') && izq.includes('X');

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Muy bien! Clasificaste correctamente los lados de la mesa.");
      } else {
        playSound('error');
        setFeedback("Casi... a la derecha de F (asientos 2 y 3) deben estar W y S.");
      }
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className={`bg-white p-6 rounded-3xl shadow-xl border-4 ${mode === 'PAR' ? 'border-pink-100' : 'border-purple-100'}`}>
        <header className="mb-4">
          <div className="flex justify-between items-center mb-2">
            <h2 className="text-xl font-bold text-pink-700">Mesa Circular</h2>
            <div className="flex bg-gray-100 p-1 rounded-xl">
              <button onClick={() => switchMode('PAR')} className={`px-3 py-1 rounded-lg text-[10px] font-bold ${mode === 'PAR' ? 'bg-pink-500 text-white shadow-sm' : 'text-gray-500'}`}>PAR</button>
              <button onClick={() => switchMode('IMPAR')} className={`px-3 py-1 rounded-lg text-[10px] font-bold ${mode === 'IMPAR' ? 'bg-purple-500 text-white shadow-sm' : 'text-gray-500'}`}>IMPAR</button>
            </div>
          </div>

          <div className="bg-pink-50 border-l-4 border-pink-400 p-3 text-[11px] text-gray-700 rounded-r-xl">
            <h4 className="font-bold mb-1 text-pink-800"><i className="fas fa-list-check mr-2"></i>Pistas:</h4>
            {mode === 'PAR' ? (
              <ul className="grid grid-cols-1 md:grid-cols-2 gap-x-4 list-disc list-inside">
                <li><strong>C</strong> en el asiento 1 (Arriba).</li>
                <li><strong>X</strong> frente a C.</li>
                <li><strong>S</strong> a la izq. de X.</li>
                <li><strong>W</strong> frente a P.</li>
                <li><strong>P</strong> junto a F.</li>
              </ul>
            ) : (
              <p>F arriba. A su <strong>derecha</strong> W y S. A su <strong>izquierda</strong> P y X.</p>
            )}
          </div>
        </header>

        <div className="flex flex-col md:flex-row gap-6 items-center justify-center py-2">
          <div className="relative">
             {/* Brújula de ayuda */}
            <div className="absolute -top-6 left-0 right-0 flex justify-between px-8 opacity-40 pointer-events-none">
               <div className="flex flex-col items-center"><i className="fas fa-arrow-left text-[10px]"></i><span className="text-[7px] font-bold">IZQUIERDA</span></div>
               <div className="flex flex-col items-center"><i className="fas fa-arrow-right text-[10px]"></i><span className="text-[7px] font-bold">DERECHA</span></div>
            </div>

            <div className={`relative w-56 h-56 md:w-72 md:h-72 rounded-full border-[8px] shadow-lg flex items-center justify-center ${mode === 'PAR' ? 'bg-pink-50 border-pink-100' : 'bg-purple-50 border-purple-100'}`}>
              <span className="text-gray-300 font-bold text-xs uppercase tracking-widest opacity-30">Mesa</span>
              {Array.from({ length: numSeats }).map((_, i) => {
                const angle = i * (360 / numSeats) - 90;
                const radius = mode === 'PAR' ? 95 : 85;
                const x = Math.cos(angle * Math.PI / 180) * radius;
                const y = Math.sin(angle * Math.PI / 180) * radius;

                return (
                  <div 
                    key={i}
                    onClick={() => toggleSeat(i)}
                    className="absolute w-10 h-10 md:w-14 md:h-14 flex items-center justify-center cursor-pointer transform -translate-x-1/2 -translate-y-1/2"
                    style={{ left: `calc(50% + ${x}px)`, top: `calc(50% + ${y}px)` }}
                  >
                    <div className={`w-full h-full rounded-full border-2 border-dashed flex items-center justify-center transition-all ${seats[i] ? 'border-solid border-pink-500 bg-white scale-110 shadow-sm' : 'border-gray-200 hover:border-pink-200'}`}>
                      {seats[i] ? (
                        <div className={`${seats[i]?.color} w-full h-full rounded-full flex items-center justify-center text-white font-bold text-[10px]`}>
                          {seats[i]?.name}
                        </div>
                      ) : (
                        <span className="text-[7px] text-gray-300 font-bold">{i + 1}</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="flex flex-wrap md:flex-col gap-1.5 justify-center">
             {available.map(p => (
               <div key={p.id} className={`${p.color} text-white px-3 py-1.5 rounded-lg shadow-sm font-bold text-[10px] min-w-[70px] text-center`}>
                 {p.name}
               </div>
             ))}
             {available.length === 0 && <span className="text-[9px] text-gray-400 italic">Mesa completa</span>}
          </div>
        </div>

        {feedback && (
          <div className={`mt-4 p-2 rounded-xl text-center text-[10px] font-bold ${feedback.includes('¡') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-6 border-t pt-4">
          <button onClick={() => switchMode(mode)} className="text-gray-300 hover:text-pink-600 font-bold text-[10px]">
            <i className="fas fa-sync-alt"></i>
          </button>
          <div className="flex gap-2">
            <button onClick={() => { playSound('pop'); onBack(); }} className="w-9 h-9 flex items-center justify-center border-2 border-gray-100 text-gray-400 rounded-xl hover:bg-gray-50">
              <i className="fas fa-chevron-left"></i>
            </button>
            <button onClick={check} className="px-4 py-1.5 bg-blue-500 text-white rounded-xl font-bold text-[10px] hover:bg-blue-600 shadow-md">
              Validar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="w-9 h-9 flex items-center justify-center bg-purple-600 text-white rounded-xl hover:bg-purple-700 shadow-md">
              <i className="fas fa-chevron-right"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CircularOrdering;

import React, { useState } from 'react';
import { playSound } from '../audio';

interface Props {
  grid: (string | null)[][];
  setGrid: React.Dispatch<React.SetStateAction<(string | null)[][]>>;
  onNext: () => void;
  onBack: () => void;
}

const TableOrdering: React.FC<Props> = ({ grid, setGrid, onNext, onBack }) => {
  const friends = ['Julio', 'Luis', 'Pedro', 'Manuel'];
  const games = ['Ajedrez', 'Damas', 'Ludo', 'Dom.'];
  const [feedback, setFeedback] = useState<string | null>(null);

  const toggleCell = (r: number, c: number) => {
    playSound('pop');
    const next = [...grid.map(row => [...row])];
    if (next[r][c] === null) next[r][c] = 'X';
    else if (next[r][c] === 'X') next[r][c] = 'O';
    else next[r][c] = null;
    setGrid(next);
  };

  const check = () => {
    const solution = [
      ['O', 'X', 'O', 'O'], // Julio: Damas
      ['O', 'O', 'O', 'X'], // Luis: Dominó
      ['X', 'O', 'O', 'O'], // Pedro: Ajedrez
      ['O', 'O', 'X', 'O'], // Manuel: Ludo
    ];

    let correct = true;
    grid.forEach((row, r) => {
      row.forEach((cell, c) => {
        if (cell === 'X' && solution[r][c] !== 'X') correct = false;
        if (solution[r][c] === 'X' && cell !== 'X') correct = false;
      });
    });

    if (correct) {
      playSound('success');
      setFeedback("¡Correcto! Tabla completada.");
    } else {
      playSound('error');
      setFeedback("Revisa: Pedro ajedrez, Luis dominó.");
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-6 rounded-3xl shadow-xl border-4 border-green-100">
        <header className="mb-6">
          <span className="text-[10px] font-bold uppercase tracking-widest text-green-400">Interactiva #4</span>
          <h2 className="text-2xl font-bold text-green-700">Doble Entrada</h2>
          <div className="bg-green-50 border-l-4 border-green-400 p-3 mt-3 text-[11px] italic text-gray-700 rounded-r-xl">
            Toca una celda: una vez para <strong>X</strong> (No), dos para <strong>O</strong> (Sí).
          </div>
        </header>

        <div className="overflow-x-auto mb-6 rounded-xl border border-gray-100">
          <table className="w-full text-[10px] md:text-xs">
            <thead>
              <tr className="bg-green-100 text-green-700">
                <th className="p-2 border border-green-200">Nombres</th>
                {games.map(g => (
                  <th key={g} className="p-2 border border-green-200">{g}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {friends.map((friend, rIdx) => (
                <tr key={friend}>
                  <td className="p-2 font-bold bg-gray-50 border border-green-100">{friend}</td>
                  {games.map((game, cIdx) => (
                    <td 
                      key={game} 
                      onClick={() => toggleCell(rIdx, cIdx)}
                      className="p-3 border border-green-100 text-center cursor-pointer hover:bg-green-50 transition-colors h-10 w-10 md:h-12 md:w-12"
                    >
                      {grid[rIdx][cIdx] === 'X' && <span className="text-red-500 font-bold">X</span>}
                      {grid[rIdx][cIdx] === 'O' && <span className="text-green-500 font-bold">O</span>}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {feedback && (
          <div className={`p-2 rounded-xl text-center text-[10px] font-bold mb-4 ${feedback.includes('¡') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center border-t pt-4">
          <button onClick={() => setGrid(Array(4).fill(null).map(() => Array(4).fill(null)))} className="text-gray-300 hover:text-green-600 font-bold text-[10px]">
            <i className="fas fa-sync-alt"></i>
          </button>
          <div className="flex gap-2">
            <button onClick={() => { playSound('pop'); onBack(); }} className="w-9 h-9 flex items-center justify-center border-2 border-gray-100 text-gray-400 rounded-xl hover:bg-gray-50">
              <i className="fas fa-chevron-left"></i>
            </button>
            <button onClick={check} className="px-4 py-1.5 bg-blue-500 text-white rounded-xl font-bold text-[10px] hover:bg-blue-600 shadow-md">
              Verificar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="w-9 h-9 flex items-center justify-center bg-purple-600 text-white rounded-xl hover:bg-purple-700 shadow-md">
              <i className="fas fa-star"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

