import React, { useState, useEffect } from 'react';
import { playSound } from '../audio';

interface Props {
  onRestart: () => void;
  onBack: () => void;
}

const PROBLEMS = [
  {
    id: 1,
    question: "6 alumnos en una montaña: Arturo está más arriba que Paulo y éste entre Hugo y Fernando. Walter está más abajo que Julio y éste un lugar más abajo que Arturo. Fernando está más arriba que Walter pero un lugar más abajo que Paulo. ¿Quién está en 3er lugar?",
    options: ["Arturo", "Julio", "Paulo", "Hugo"],
    answer: "Paulo",
    explanation: "El orden es: Arturo (1), Julio (2), Paulo (3), Fernando (4)..."
  },
  {
    id: 2,
    question: "En un edificio de 6 pisos, el 4to está vacío. Pedidos adyacente a Mercantil y Comercial. Recursos no está en el último piso. ¿Qué es verdadero?",
    options: ["Mercantil no está en el 3ero", "Recursos no está en el 5to", "Gestión está en el 1ero", "Comercial abajo de Mercantil"],
    answer: "Recursos no está en el 5to piso",
    explanation: "Por descarte de posiciones y adyacencia."
  },
  {
    id: 3,
    question: "Mesa circular, 6 asientos. Luis no al lado de Antonio ni Rosa. Andrea a la derecha de Antonio. ¿Quién a la izquierda de Lidia?",
    options: ["Antonio", "Carlos", "Luis", "Andrea"],
    answer: "Luis",
    explanation: "Las restricciones fuerzan a Luis a esa posición opuesta."
  }
];

const Challenge: React.FC<Props> = ({ onRestart, onBack }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [score, setScore] = useState(0);
  const [finished, setFinished] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  useEffect(() => {
    if (finished) playSound('finish');
  }, [finished]);

  const handleVerify = () => {
    if (selectedOption === PROBLEMS[currentStep].answer) {
      playSound('success');
      setScore(s => s + 1);
    } else {
      playSound('error');
    }
    setShowFeedback(true);
  };

  const handleNext = () => {
    playSound('pop');
    if (currentStep < PROBLEMS.length - 1) {
      setCurrentStep(s => s + 1);
      setSelectedOption(null);
      setShowFeedback(false);
    } else {
      setFinished(true);
    }
  };

  if (finished) {
    return (
      <div className="max-w-md mx-auto text-center py-6 animate-fadeIn">
        <div className="bg-white p-8 rounded-3xl shadow-xl border-4 border-purple-200">
          <div className="text-4xl mb-4">🏆</div>
          <h2 className="text-2xl font-bold mb-2">¡Finalizado!</h2>
          <p className="text-lg mb-6 font-bold text-purple-600">{score} de {PROBLEMS.length} correctas</p>
          <button onClick={onRestart} className="w-full py-3 bg-purple-600 text-white rounded-xl font-bold">Reiniciar todo</button>
        </div>
      </div>
    );
  }

  const p = PROBLEMS[currentStep];

  return (
    <div className="max-w-2xl mx-auto animate-slideIn">
      <div className="bg-white rounded-3xl overflow-hidden shadow-xl border border-gray-100">
        <div className="bg-gradient-to-r from-purple-600 to-blue-500 p-4 text-white flex justify-between items-center">
          <span className="text-[10px] font-bold">Reto {currentStep + 1} de {PROBLEMS.length}</span>
          <span className="text-[10px] opacity-75">{Math.round(((currentStep)/PROBLEMS.length)*100)}%</span>
        </div>

        <div className="p-6">
          <p className="text-sm text-gray-700 leading-relaxed mb-6 bg-gray-50 p-4 rounded-xl italic">"{p.question}"</p>

          <div className="grid grid-cols-1 gap-2">
            {p.options.map(opt => (
              <button
                key={opt}
                disabled={showFeedback}
                onClick={() => { playSound('pop'); setSelectedOption(opt); }}
                className={`p-3 rounded-xl border text-xs font-bold text-left transition-all ${selectedOption === opt ? 'border-purple-500 bg-purple-50' : 'border-gray-100'}`}
              >
                {opt}
              </button>
            ))}
          </div>

          {showFeedback && (
            <div className={`mt-4 p-3 rounded-lg text-[10px] ${selectedOption === p.answer ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
              <strong>{selectedOption === p.answer ? '✓ Correcto' : '✗ Incorrecto'}</strong>: {p.explanation}
            </div>
          )}

          <div className="mt-8 flex justify-between items-center gap-2">
            {!showFeedback ? (
              <>
                <button onClick={onBack} className="px-4 py-2 border border-gray-200 text-gray-400 rounded-lg text-[10px] font-bold">Regresar</button>
                <button 
                  disabled={!selectedOption}
                  onClick={handleVerify}
                  className={`flex-grow py-2 rounded-lg text-[10px] font-bold text-white shadow-md ${selectedOption ? 'bg-blue-500' : 'bg-gray-200'}`}
                >
                  Verificar
                </button>
              </>
            ) : (
              <button onClick={handleNext} className="w-full py-3 bg-purple-600 text-white rounded-xl font-bold text-xs shadow-lg">
                Siguiente problema <i className="fas fa-chevron-right ml-2"></i>
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Challenge;

import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  slots: (Person | null)[];
  setSlots: React.Dispatch<React.SetStateAction<(Person | null)[]>>;
  available: Person[];
  setAvailable: React.Dispatch<React.SetStateAction<Person[]>>;
  onNext: () => void;
  onBack: () => void;
}

const INITIAL_PEOPLE: Person[] = [
  { id: '1', name: 'María', color: 'bg-red-400' },
  { id: '2', name: 'Juana', color: 'bg-blue-400' },
  { id: '3', name: 'Ana', color: 'bg-green-400' },
  { id: '4', name: 'Inés', color: 'bg-yellow-400' },
  { id: '5', name: 'Enma', color: 'bg-pink-400' },
];

const HorizontalOrdering: React.FC<Props> = ({ slots, setSlots, available, setAvailable, onNext, onBack }) => {
  const [feedback, setFeedback] = useState<string | null>(null);

  const handlePlace = (person: Person, index: number) => {
    playSound('pop');
    const newSlots = [...slots];
    const oldPerson = newSlots[index];

    newSlots[index] = person;
    setSlots(newSlots);

    setAvailable(prev => {
      const filtered = prev.filter(p => p.id !== person.id);
      if (oldPerson) return [...filtered, oldPerson];
      return filtered;
    });
  };

  const handleRemove = (index: number) => {
    const s = slots[index];
    if (s) {
      playSound('pop');
      setSlots(prev => {
        const next = [...prev];
        next[index] = null;
        return next;
      });
      setAvailable(prev => [...prev, s]);
    }
  };

  const reset = () => {
    playSound('pop');
    setSlots(Array(5).fill(null));
    setAvailable(INITIAL_PEOPLE);
    setFeedback(null);
  };

  const check = () => {
    const correctNames = ['Inés', 'Enma', 'Ana', 'Juana', 'María'];
    const currentNames = slots.map(s => s?.name);

    if (currentNames.every((name, i) => name === correctNames[i])) {
      playSound('success');
      setFeedback("¡Excelente! Has ordenado correctamente de menor a mayor.");
    } else {
      playSound('error');
      setFeedback("Casi lo tienes. Revisa: 'María es la mayor', 'Inés la menor' y 'Enma es menor que Ana'.");
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-5 md:p-8 rounded-3xl shadow-xl border-4 border-purple-100">
        <header className="mb-6">
          <span className="text-[10px] font-bold uppercase tracking-widest text-purple-400">Interactiva #1</span>
          <h2 className="text-xl md:text-2xl font-bold text-purple-700">Ordenamiento Horizontal</h2>
          <div className="bg-purple-50 border-l-4 border-purple-400 p-3 mt-3 text-[11px] italic text-gray-700 rounded-r-xl">
            "María es la mayor. Enma es menor que Ana. Juana es mayor que Ana. Inés es la más joven."
          </div>
        </header>

        <div className="flex flex-wrap gap-2 justify-center mb-8 min-h-[50px]">
          {available.map(p => (
            <button
              key={p.id}
              onClick={() => {
                const emptyIdx = slots.findIndex(s => s === null);
                if (emptyIdx !== -1) handlePlace(p, emptyIdx);
              }}
              className={`${p.color} text-white px-3 py-1.5 rounded-xl shadow-md font-bold text-xs hover:scale-105 transition-transform`}
            >
              {p.name}
            </button>
          ))}
        </div>

        <div className="relative mb-10 px-4">
          <div className="h-1 bg-gray-200 w-full rounded-full absolute top-1/2 -translate-y-1/2 left-0"></div>
          <div className="flex justify-between relative z-10">
            {slots.map((s, i) => (
              <div key={i} className="flex flex-col items-center">
                <div 
                  onClick={() => handleRemove(i)}
                  className={`w-10 h-10 md:w-16 md:h-16 rounded-full border-2 border-dashed border-purple-200 flex items-center justify-center cursor-pointer transition-all ${s ? 'border-solid border-purple-500 bg-white shadow-sm scale-110' : 'hover:border-purple-300'}`}
                >
                  {s ? (
                    <div className={`${s.color} w-full h-full rounded-full flex items-center justify-center text-white font-bold text-[9px] md:text-xs`}>
                      {s.name}
                    </div>
                  ) : (
                    <span className="text-gray-300 text-[7px] md:text-[8px]">?</span>
                  )}
                </div>
                <span className="mt-2 text-[7px] md:text-[8px] uppercase font-bold text-gray-400">
                  {i === 0 ? 'Menor' : i === 4 ? 'Mayor' : ''}
                </span>
              </div>
            ))}
          </div>
        </div>

        {feedback && (
          <div className={`p-3 rounded-xl mb-6 text-center text-[10px] md:text-xs font-bold ${feedback.includes('Excelente') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center border-t pt-4">
          <button onClick={reset} className="text-gray-300 hover:text-purple-600 font-bold text-[10px]">
            <i className="fas fa-sync-alt"></i>
          </button>
          <div className="flex gap-2">
            <button onClick={() => { playSound('pop'); onBack(); }} className="w-9 h-9 flex items-center justify-center border-2 border-gray-100 text-gray-400 rounded-xl hover:bg-gray-50 transition-all">
              <i className="fas fa-arrow-left"></i>
            </button>
            <button onClick={check} className="px-4 py-1.5 bg-blue-500 text-white rounded-xl font-bold text-[10px] hover:bg-blue-600 shadow-md">
              Validar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="w-9 h-9 flex items-center justify-center bg-purple-600 text-white rounded-xl hover:bg-purple-700 shadow-md transition-all">
              <i className="fas fa-arrow-right"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HorizontalOrdering;

import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  mode: 'PAR' | 'IMPAR';
  setMode: React.Dispatch<React.SetStateAction<'PAR' | 'IMPAR'>>;
  seats: (Person | null)[];
  setSeats: React.Dispatch<React.SetStateAction<(Person | null)[]>>;
  available: Person[];
  setAvailable: React.Dispatch<React.SetStateAction<Person[]>>;
  onNext: () => void;
  onBack: () => void;
}

const PEOPLE_PAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'a', name: 'A', color: 'bg-blue-400' },
  { id: 'c', name: 'C', color: 'bg-green-400' },
  { id: 'f', name: 'F', color: 'bg-yellow-400' },
  { id: 'p', name: 'P', color: 'bg-purple-400' },
  { id: 'b', name: 'B', color: 'bg-pink-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const PEOPLE_IMPAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'f', name: 'F', color: 'bg-green-400' },
  { id: 'p', name: 'P', color: 'bg-blue-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const CircularOrdering: React.FC<Props> = ({ mode, setMode, seats, setSeats, available, setAvailable, onNext, onBack }) => {
  const [feedback, setFeedback] = useState<string | null>(null);
  const numSeats = mode === 'PAR' ? 8 : 5;

  const switchMode = (newMode: 'PAR' | 'IMPAR') => {
    playSound('pop');
    setMode(newMode);
    setSeats(Array(newMode === 'PAR' ? 8 : 5).fill(null));
    setAvailable(newMode === 'PAR' ? PEOPLE_PAR : PEOPLE_IMPAR);
    setFeedback(null);
  };

  const toggleSeat = (idx: number) => {
    playSound('pop');
    if (seats[idx]) {
      const person = seats[idx]!;
      setAvailable(prev => [...prev, person]);
      setSeats(prev => {
        const next = [...prev];
        next[idx] = null;
        return next;
      });
    } else if (available.length > 0) {
      const person = available[0];
      setSeats(prev => {
        const next = [...prev];
        next[idx] = person;
        return next;
      });
      setAvailable(prev => prev.slice(1));
    }
  };

  const check = () => {
    const names = seats.map(s => s?.name || '');
    if (names.includes('')) {
      playSound('error');
      setFeedback("Por favor, ubica a todas las personas en la mesa.");
      return;
    }

    // Perspectiva visual:
    // Asiento 0: Superior (C o F)
    // Asientos 1, 2, 3: Derecha visual (sentido horario)
    // Asientos 7, 6, 5: Izquierda visual (sentido anti-horario)

    if (mode === 'PAR') {
      const cIdx = names.indexOf('C');
      if (cIdx !== 0) { playSound('error'); setFeedback("Coloca a C arriba (asiento 1)."); return; }

      const getAt = (idx: number) => names[idx];
      // Solución esperada basada en las pistas:
      // 0: C, 4: X (Frente), 5: S (Izq visual de X), 1: F (Frente a S), 2: P (Junto F), 6: W (Frente P)
      const isCorrect = 
        getAt(4) === 'X' && // X frente a C
        getAt(5) === 'S' && // S a la izq de X (anti-horario)
        getAt(1) === 'F' && // S frente a F (5 frente a 1)
        getAt(2) === 'P' && // P junto a F
        getAt(6) === 'W';   // W frente a P (6 frente a 2)

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Excelente! Has resuelto la lógica circular.");
      } else {
        playSound('error');
        setFeedback("Revisa: W debe estar frente a P, y S junto a la izquierda de X.");
      }
    } else {
      const fIdx = names.indexOf('F');
      if (fIdx !== 0) { playSound('error'); setFeedback("Coloca a F arriba."); return; }

      // Derecha visual de F (espectador): 1, 2. Izquierda: 4, 3.
      const der = [names[1], names[2]];
      const izq = [names[4], names[3]];

      const isCorrect = 
        der.includes('W') && der.includes('S') && 
        izq.includes('P') && izq.includes('X');

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Muy bien! Ordenaste correctamente los lados.");
      } else {
        playSound('error');
        setFeedback("A la derecha de F deben estar W y S.");
      }
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className={`bg-white p-5 rounded-3xl shadow-xl border-4 ${mode === 'PAR' ? 'border-pink-100' : 'border-purple-100'}`}>
        <header className="mb-4">
          <div className="flex justify-between items-center mb-2">
            <h2 className="text-xl font-bold text-pink-700">Mesa Circular</h2>
            <div className="flex bg-gray-100 p-1 rounded-xl shrink-0">
              <button onClick={() => switchMode('PAR')} className={`px-2 py-1 rounded-lg text-[9px] font-bold ${mode === 'PAR' ? 'bg-pink-500 text-white' : 'text-gray-500'}`}>PAR</button>
              <button onClick={() => switchMode('IMPAR')} className={`px-2 py-1 rounded-lg text-[9px] font-bold ${mode === 'IMPAR' ? 'bg-purple-500 text-white' : 'text-gray-500'}`}>IMPAR</button>
            </div>
          </div>

          <div className="bg-pink-50 border-l-4 border-pink-400 p-3 text-[10px] text-gray-700 rounded-r-xl">
            <h4 className="font-bold mb-1 text-pink-800"><i className="fas fa-list-check mr-2"></i>Reglas:</h4>
            {mode === 'PAR' ? (
              <ul className="grid grid-cols-1 md:grid-cols-2 gap-x-2">
                <li>• <strong>C</strong> en el asiento 1 (Arriba).</li>
                <li>• <strong>X</strong> frente a C.</li>
                <li>• <strong>S</strong> junto a la izq. de X.</li>
                <li>• <strong>W</strong> frente a P.</li>
                <li>• <strong>P</strong> junto a F.</li>
              </ul>
            ) : (
              <p>• F arriba. Derecha: W y S. Izquierda: P y X.</p>
            )}
          </div>
        </header>

        <div className="flex flex-col md:flex-row gap-4 items-center justify-center py-2">
          <div className="relative">
            <div className="absolute -top-4 left-0 right-0 flex justify-between px-6 opacity-40 text-[8px] font-bold">
               <span><i className="fas fa-arrow-left"></i> IZQ</span>
               <span>DER <i className="fas fa-arrow-right"></i></span>
            </div>

            <div className={`relative w-52 h-52 md:w-64 md:h-64 rounded-full border-8 shadow-inner flex items-center justify-center ${mode === 'PAR' ? 'bg-pink-50/50 border-pink-100' : 'bg-purple-50/50 border-purple-100'}`}>
              <span className="text-gray-200 font-bold text-[8px] tracking-widest uppercase">Mesa</span>
              {Array.from({ length: numSeats }).map((_, i) => {
                const angle = i * (360 / numSeats) - 90;
                const radius = mode === 'PAR' ? 85 : 75;
                const x = Math.cos(angle * Math.PI / 180) * radius;
                const y = Math.sin(angle * Math.PI / 180) * radius;

                return (
                  <div 
                    key={i}
                    onClick={() => toggleSeat(i)}
                    className="absolute w-10 h-10 md:w-12 md:h-12 flex items-center justify-center cursor-pointer transform -translate-x-1/2 -translate-y-1/2"
                    style={{ left: `calc(50% + ${x}px)`, top: `calc(50% + ${y}px)` }}
                  >
                    <div className={`w-full h-full rounded-full border-2 border-dashed flex items-center justify-center transition-all ${seats[i] ? 'border-solid border-pink-500 bg-white scale-110' : 'border-gray-200 hover:border-pink-200'}`}>
                      {seats[i] ? (
                        <div className={`${seats[i]?.color} w-full h-full rounded-full flex items-center justify-center text-white font-bold text-[9px]`}>
                          {seats[i]?.name}
                        </div>
                      ) : (
                        <span className="text-[7px] text-gray-300 font-bold">{i + 1}</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="flex flex-wrap md:flex-col gap-1.5 justify-center">
             {available.map(p => (
               <div key={p.id} className={`${p.color} text-white px-2 py-1 rounded-lg shadow-sm font-bold text-[9px] min-w-[60px] text-center`}>
                 {p.name}
               </div>
             ))}
          </div>
        </div>

        {feedback && (
          <div className={`mt-4 p-2 rounded-xl text-center text-[9px] font-bold ${feedback.includes('¡') ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-6 border-t pt-4">
          <button onClick={() => switchMode(mode)} className="text-gray-300 hover:text-pink-600 font-bold text-[10px]">
            <i className="fas fa-sync-alt"></i>
          </button>
          <div className="flex gap-2">
            <button onClick={() => { playSound('pop'); onBack(); }} className="w-8 h-8 flex items-center justify-center border-2 border-gray-100 text-gray-400 rounded-xl hover:bg-gray-50 transition-all">
              <i className="fas fa-arrow-left"></i>
            </button>
            <button onClick={check} className="px-3 py-1 bg-blue-500 text-white rounded-xl font-bold text-[10px] hover:bg-blue-600 shadow-md">
              Validar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="w-8 h-8 flex items-center justify-center bg-purple-600 text-white rounded-xl hover:bg-purple-700 shadow-md transition-all">
              <i className="fas fa-arrow-right"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CircularOrdering;

import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  floors: (Person | null)[];
  setFloors: React.Dispatch<React.SetStateAction<(Person | null)[]>>;
  available: Person[];
  setAvailable: React.Dispatch<React.SetStateAction<Person[]>>;
  onNext: () => void;
  onBack: () => void;
}

const INITIAL_VERTICAL: Person[] = [
  { id: 'p1', name: 'Raúl', color: 'bg-orange-400' },
  { id: 'p2', name: 'Pedro', color: 'bg-indigo-400' },
  { id: 'p3', name: 'Carlos', color: 'bg-emerald-400' },
  { id: 'p4', name: 'Julio', color: 'bg-rose-400' },
];

const VerticalOrdering: React.FC<Props> = ({ floors, setFloors, available, setAvailable, onNext, onBack }) => {
  const [feedback, setFeedback] = useState<string | null>(null);

  const handlePlace = (person: Person, floorIdx: number) => {
    playSound('pop');
    const newFloors = [...floors];
    const oldPerson = newFloors[floorIdx];
    newFloors[floorIdx] = person;
    setFloors(newFloors);
    setAvailable(prev => {
      const filtered = prev.filter(p => p.id !== person.id);
      if (oldPerson) return [...filtered, oldPerson];
      return filtered;
    });
  };

  const handleRemove = (idx: number) => {
    if (floors[idx]) {
      playSound('pop');
      setAvailable(prev => [...prev, floors[idx]!]);
      setFloors(prev => {
        const next = [...prev];
        next[idx] = null;
        return next;
      });
    }
  };

  const check = () => {
    const correctNames = ['Raúl', 'Pedro', 'Julio', 'Carlos'];
    const currentNames = floors.map(f => f?.name);

    if (currentNames.every((name, i) => name === correctNames[i])) {
      playSound('success');
      setFeedback("¡Correcto! Julio vive en el 3er piso.");
    } else {
      playSound('error');
      setFeedback("Revisa bien: Raúl va en el primero, y Julio vive justo arriba de Pedro.");
    }
  };

  const reset = () => {
    playSound('pop');
    setFloors(Array(4).fill(null)); 
    setAvailable(INITIAL_VERTICAL); 
    setFeedback(null);
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className="bg-white p-5 md:p-8 rounded-3xl shadow-xl border-4 border-blue-100">
        <header className="mb-6">
          <span className="text-[10px] font-bold uppercase tracking-widest text-blue-400">Interactiva #2</span>
          <h2 className="text-xl md:text-2xl font-bold text-blue-700">Ordenamiento Vertical</h2>
          <div className="bg-blue-50 border-l-4 border-blue-400 p-3 mt-3 text-[11px] italic text-gray-700 rounded-r-xl">
            "Raúl en el 1er piso. Carlos arriba de todos. Julio un piso arriba de Pedro."
          </div>
        </header>

        <div className="flex flex-col md:flex-row gap-8 items-center justify-center">
          <div className="w-40 bg-gray-100 p-3 rounded-2xl border-4 border-gray-200">
            {[3, 2, 1, 0].map(idx => (
              <div 
                key={idx} 
                onClick={() => handleRemove(idx)}
                className={`h-12 md:h-16 mb-2 last:mb-0 rounded-xl border-2 border-dashed flex items-center justify-center cursor-pointer transition-all ${floors[idx] ? 'bg-white border-blue-400 shadow-sm' : 'border-gray-300 hover:border-blue-200'}`}
              >
                {floors[idx] ? (
                  <div className={`flex items-center gap-2 ${floors[idx]?.color} text-white px-2 py-1 rounded-lg font-bold text-[10px] w-full mx-1 justify-center`}>
                    {floors[idx]?.name}
                  </div>
                ) : (
                  <span className="text-gray-300 font-bold text-[9px]">Piso {idx + 1}</span>
                )}
              </div>
            ))}
          </div>

          <div className="flex flex-wrap md:flex-col gap-2 justify-center">
            {available.map(p => (
              <button
                key={p.id}
                onClick={() => {
                  const emptyIdx = floors.findIndex(f => f === null);
                  if (emptyIdx !== -1) handlePlace(p, emptyIdx);
                }}
                className={`${p.color} text-white px-3 py-1.5 rounded-xl shadow-md font-bold text-[10px] flex items-center gap-2 hover:scale-105 transition-all`}
              >
                <span>{p.name}</span>
                <i className="fas fa-plus-circle opacity-50"></i>
              </button>
            ))}
          </div>
        </div>

        {feedback && (
          <div className={`mt-6 p-2 rounded-xl text-center text-[10px] font-bold ${feedback.includes('¡Correcto!') ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-8 border-t pt-4">
          <button onClick={reset} className="text-gray-300 hover:text-blue-600 font-bold text-[10px]">
            <i className="fas fa-sync-alt"></i>
          </button>
          <div className="flex gap-2">
            <button onClick={() => { playSound('pop'); onBack(); }} className="w-8 h-8 flex items-center justify-center border-2 border-gray-100 text-gray-400 rounded-xl hover:bg-gray-50 transition-all">
              <i className="fas fa-arrow-left"></i>
            </button>
            <button onClick={check} className="px-3 py-1 bg-blue-500 text-white rounded-xl font-bold text-[10px] hover:bg-blue-600 shadow-md">
              Validar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="w-8 h-8 flex items-center justify-center bg-purple-600 text-white rounded-xl hover:bg-purple-700 shadow-md transition-all">
              <i className="fas fa-arrow-right"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default VerticalOrdering;

import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  slots: (Person | null)[];
  setSlots: React.Dispatch<React.SetStateAction<(Person | null)[]>>;
  available: Person[];
  setAvailable: React.Dispatch<React.SetStateAction<Person[]>>;
  onNext: () => void;
  onBack: () => void;
}

const INITIAL_PEOPLE: Person[] = [
  { id: '1', name: 'María', color: 'bg-red-400' },
  { id: '2', name: 'Juana', color: 'bg-blue-400' },
  { id: '3', name: 'Ana', color: 'bg-green-400' },
  { id: '4', name: 'Inés', color: 'bg-yellow-400' },
  { id: '5', name: 'Enma', color: 'bg-pink-400' },
];

const HorizontalOrdering: React.FC<Props> = ({ slots, setSlots, available, setAvailable, onNext, onBack }) => {
  const [feedback, setFeedback] = useState<string | null>(null);

  const handlePlace = (person: Person, index: number) => {
    playSound('pop');
    const newSlots = [...slots];
    const oldPerson = newSlots[index];

    newSlots[index] = person;
    setSlots(newSlots);

    setAvailable(prev => {
      const filtered = prev.filter(p => p.id !== person.id);
      if (oldPerson) return [...filtered, oldPerson];
      return filtered;
    });
  };

  const handleRemove = (index: number) => {
    const s = slots[index];
    if (s) {
      playSound('pop');
      setSlots(prev => {
        const next = [...prev];
        next[index] = null;
        return next;
      });
      setAvailable(prev => [...prev, s]);
    }
  };

  const reset = () => {
    playSound('pop');
    setSlots(Array(5).fill(null));
    setAvailable(INITIAL_PEOPLE);
    setFeedback(null);
  };

  const check = () => {
    const correctNames = ['Inés', 'Enma', 'Ana', 'Juana', 'María'];
    const currentNames = slots.map(s => s?.name);

    if (currentNames.every((name, i) => name === correctNames[i])) {
