import React, { useState } from 'react';
import { Person } from '../types';
import { playSound } from '../audio';

interface Props {
  mode: 'PAR' | 'IMPAR';
  setMode: React.Dispatch<React.SetStateAction<'PAR' | 'IMPAR'>>;
  seats: (Person | null)[];
  setSeats: React.Dispatch<React.SetStateAction<(Person | null)[]>>;
  available: Person[];
  setAvailable: React.Dispatch<React.SetStateAction<Person[]>>;
  onNext: () => void;
  onBack: () => void;
}

const PEOPLE_PAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'a', name: 'A', color: 'bg-blue-400' },
  { id: 'c', name: 'C', color: 'bg-green-400' },
  { id: 'f', name: 'F', color: 'bg-yellow-400' },
  { id: 'p', name: 'P', color: 'bg-purple-400' },
  { id: 'b', name: 'B', color: 'bg-pink-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const PEOPLE_IMPAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'f', name: 'F', color: 'bg-green-400' },
  { id: 'p', name: 'P', color: 'bg-blue-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const CircularOrdering: React.FC<Props> = ({ mode, setMode, seats, setSeats, available, setAvailable, onNext, onBack }) => {
  const [feedback, setFeedback] = useState<string | null>(null);
  const numSeats = mode === 'PAR' ? 8 : 5;

  const switchMode = (newMode: 'PAR' | 'IMPAR') => {
    playSound('pop');
    setMode(newMode);
    setSeats(Array(newMode === 'PAR' ? 8 : 5).fill(null));
    setAvailable(newMode === 'PAR' ? PEOPLE_PAR : PEOPLE_IMPAR);
    setFeedback(null);
  };

  const toggleSeat = (idx: number) => {
    playSound('pop');
    if (seats[idx]) {
      const person = seats[idx]!;
      setAvailable(prev => [...prev, person]);
      setSeats(prev => {
        const next = [...prev];
        next[idx] = null;
        return next;
      });
    } else if (available.length > 0) {
      const person = available[0];
      setSeats(prev => {
        const next = [...prev];
        next[idx] = person;
        return next;
      });
      setAvailable(prev => prev.slice(1));
    }
  };

  const check = () => {
    const names = seats.map(s => s?.name || '');
    if (names.includes('')) {
      playSound('error');
      setFeedback("Por favor, ubica a todas las personas en la mesa.");
      return;
    }

    /**
     * Lógica según la instrucción del usuario:
     * - En contra de las manecillas (CCW) es DERECHA.
     * - A favor de las manecillas (CW) es IZQUIERDA.
     * 
     * Mapeo de índices (Visual):
     * 0: Arriba
     * 1, 2, 3...: CW (A favor del reloj) -> IZQUIERDA
     * 7, 6, 5...: CCW (En contra del reloj) -> DERECHA
     */

    if (mode === 'PAR') {
      const cIdx = names.indexOf('C');
      if (cIdx !== 0) { playSound('error'); setFeedback("Coloca a C arriba (asiento 1)."); return; }

      const idxW = names.indexOf('W');
      const idxP = names.indexOf('P');
      const idxS = names.indexOf('S');
      const idxF = names.indexOf('F');
      const idxX = names.indexOf('X');
      const idxB = names.indexOf('B');

      // W frente a P (separados por 4 asientos)
      const wFrenteP = Math.abs(idxW - idxP) === 4;
      // S frente a F
      const sFrenteF = Math.abs(idxS - idxF) === 4;
      // S a la izquierda de X (Izquierda = CW = +1)
      const sIzqX = idxS === (idxX + 1) % 8;
      // P entre B y F (Adyacentes)
      const pEntreByF = 
        (idxB === (idxP + 1) % 8 && idxF === (idxP - 1 + 8) % 8) ||
        (idxF === (idxP + 1) % 8 && idxB === (idxP - 1 + 8) % 8);

      if (wFrenteP && sFrenteF && sIzqX && pEntreByF) {
        playSound('success');
        setFeedback("¡Excelente! Has resuelto la lógica circular PAR.");
      } else {
        playSound('error');
        let errorMsg = "Revisa: ";
        if (!wFrenteP) errorMsg += "W debe estar frente a P. ";
        if (!sFrenteF) errorMsg += "S debe estar frente a F. ";
        if (!sIzqX) errorMsg += "S debe estar a la izquierda (CW) de X. ";
        if (!pEntreByF) errorMsg += "P debe estar entre B y F. ";
        setFeedback(errorMsg);
      }
    } else {
      const fIdx = names.indexOf('F');
      if (fIdx !== 0) { playSound('error'); setFeedback("Coloca a F arriba."); return; }

      // Perspectiva de F (asiento 0):
      // Derecha (CCW): índices 4, 3
      // Izquierda (CW): índices 1, 2
      const der = [names[4], names[3]];
      const izq = [names[1], names[2]];

      const isCorrect = 
        der.includes('W') && der.includes('S') && 
        izq.includes('P') && izq.includes('X');

      if (isCorrect) {
        playSound('success');
        setFeedback("¡Muy bien! Ordenaste correctamente los lados de la mesa impar.");
      } else {
        playSound('error');
        setFeedback("Casi... a la derecha de F (CCW) deben estar W y S.");
      }
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn">
      <div className={`bg-white p-5 rounded-3xl shadow-xl border-4 ${mode === 'PAR' ? 'border-pink-100' : 'border-purple-100'}`}>
        <header className="mb-4">
          <div className="flex justify-between items-center mb-2">
            <h2 className="text-xl font-bold text-pink-700">Mesa Circular</h2>
            <div className="flex bg-gray-100 p-1 rounded-xl shrink-0">
              <button onClick={() => switchMode('PAR')} className={`px-2 py-1 rounded-lg text-[9px] font-bold ${mode === 'PAR' ? 'bg-pink-500 text-white' : 'text-gray-500'}`}>PAR</button>
              <button onClick={() => switchMode('IMPAR')} className={`px-2 py-1 rounded-lg text-[9px] font-bold ${mode === 'IMPAR' ? 'bg-purple-500 text-white' : 'text-gray-500'}`}>IMPAR</button>
            </div>
          </div>

          <div className="bg-pink-50 border-l-4 border-pink-400 p-3 text-[10px] text-gray-700 rounded-r-xl">
            <h4 className="font-bold mb-1 text-pink-800"><i className="fas fa-list-check mr-2"></i>Reglas:</h4>
            {mode === 'PAR' ? (
              <ul className="grid grid-cols-1 md:grid-cols-2 gap-x-2">
                <li>• <strong>C</strong> en el asiento 1 (Arriba).</li>
                <li>• <strong>W</strong> frente a <strong>P</strong>.</li>
                <li>• <strong>S</strong> frente a <strong>F</strong>.</li>
                <li>• <strong>S</strong> a la izquierda (CW) de <strong>X</strong>.</li>
                <li>• <strong>P</strong> entre <strong>B</strong> y <strong>F</strong>.</li>
              </ul>
            ) : (
              <p>• F arriba. A su <strong>derecha</strong> (CCW) W y S. A su <strong>izquierda</strong> (CW) P y X.</p>
            )}
          </div>
        </header>

        <div className="flex flex-col md:flex-row gap-4 items-center justify-center py-2">
          <div className="relative">
            <div className="absolute -top-4 left-0 right-0 flex justify-between px-6 opacity-60 text-[8px] font-extrabold text-gray-500">
               <span className="flex flex-col items-center">
                 <i className="fas fa-arrow-rotate-right text-purple-400 mb-0.5"></i>
                 <span>IZQ (CW)</span>
               </span>
               <span className="flex flex-col items-center">
                 <i className="fas fa-arrow-rotate-left text-pink-400 mb-0.5"></i>
                 <span>DER (CCW)</span>
               </span>
            </div>

            <div className={`relative w-56 h-56 md:w-72 md:h-72 rounded-full border-8 shadow-inner flex items-center justify-center ${mode === 'PAR' ? 'bg-pink-50/50 border-pink-100' : 'bg-purple-50/50 border-purple-100'}`}>
              <span className="text-gray-200 font-bold text-[8px] tracking-widest uppercase">Perspectiva Seated</span>
              {Array.from({ length: numSeats }).map((_, i) => {
                const angle = i * (360 / numSeats) - 90;
                const radius = mode === 'PAR' ? 95 : 85;
                const x = Math.cos(angle * Math.PI / 180) * radius;
                const y = Math.sin(angle * Math.PI / 180) * radius;

                return (
                  <div 
                    key={i}
                    onClick={() => toggleSeat(i)}
                    className="absolute w-10 h-10 md:w-14 md:h-14 flex items-center justify-center cursor-pointer transform -translate-x-1/2 -translate-y-1/2"
                    style={{ left: `calc(50% + ${x}px)`, top: `calc(50% + ${y}px)` }}
                  >
                    <div className={`w-full h-full rounded-full border-2 border-dashed flex items-center justify-center transition-all ${seats[i] ? 'border-solid border-pink-500 bg-white scale-110 shadow-sm' : 'border-gray-200 hover:border-pink-200'}`}>
                      {seats[i] ? (
                        <div className={`${seats[i]?.color} w-full h-full rounded-full flex items-center justify-center text-white font-bold text-[10px]`}>
                          {seats[i]?.name}
                        </div>
                      ) : (
                        <span className="text-[8px] text-gray-300 font-bold">{i + 1}</span>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          <div className="flex flex-wrap md:flex-col gap-1.5 justify-center">
             {available.map(p => (
               <div key={p.id} className={`${p.color} text-white px-3 py-1.5 rounded-lg shadow-sm font-bold text-[10px] min-w-[70px] text-center`}>
                 {p.name}
               </div>
             ))}
          </div>
        </div>

        {feedback && (
          <div className={`mt-4 p-2 rounded-xl text-center text-[10px] font-bold ${feedback.includes('¡') ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            {feedback}
          </div>
        )}

        <div className="flex justify-between items-center mt-6 border-t pt-4">
          <button onClick={() => switchMode(mode)} className="text-gray-300 hover:text-pink-600 font-bold text-[10px]">
            <i className="fas fa-sync-alt"></i>
          </button>
          <div className="flex gap-2">
            <button onClick={() => { playSound('pop'); onBack(); }} className="w-10 h-10 flex items-center justify-center border-2 border-gray-100 text-gray-400 rounded-xl hover:bg-gray-50 transition-all">
              <i className="fas fa-arrow-left"></i>
            </button>
            <button onClick={check} className="px-5 py-2 bg-blue-500 text-white rounded-xl font-bold text-xs hover:bg-blue-600 shadow-md">
              Validar
            </button>
            <button onClick={() => { playSound('pop'); onNext(); }} className="w-10 h-10 flex items-center justify-center bg-purple-600 text-white rounded-xl hover:bg-purple-700 shadow-md transition-all">
              <i className="fas fa-arrow-right"></i>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

