export enum View {
  WELCOME = 'WELCOME',
  MENU = 'MENU',
  THEORY = 'THEORY',
  HORIZONTAL = 'HORIZONTAL',
  VERTICAL = 'VERTICAL',
  CIRCULAR = 'CIRCULAR',
  TABLE = 'TABLE',
  CHALLENGE = 'CHALLENGE'
}

export interface StudentProfile {
  name: string;
