    id: 5,
    title: "Reto 5: Globos de Colores",
    question: "Javi, Lola, Dani y Sol tienen globos de colores: Rojo, Azul, Verde y Amarillo. Sol tiene el verde. El globo de Dani no es ni rojo ni azul. Javi tiene el rojo. ¿De qué color es el globo de Lola?",
    options: ["Azul", "Amarillo", "Verde", "Rojo"],
    answer: "Azul",
    explanation: "Sol: Verde. Javi: Rojo. Dani: Si no es rojo ni azul, y el verde ya es de Sol, Dani tiene el Amarillo. Lola se queda con el Azul."
  }
];

const Challenge: React.FC<Props> = ({ student, onRestart, onBack }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [score, setScore] = useState(0);
  const [finished, setFinished] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  const handleVerify = () => {
    if (selectedOption === PROBLEMS[currentStep].answer) {
      playSound('success');
      setScore(s => s + 1);
    } else {
      playSound('error');
    }
    setShowFeedback(true);
  };

  const handleNext = () => {
    playSound('pop');
    if (currentStep < PROBLEMS.length - 1) {
      setCurrentStep(s => s + 1);
      setSelectedOption(null);
      setShowFeedback(false);
    } else {
      setFinished(true);
      playSound('finish');
    }
  };

  if (finished) {
    const totalSims = Object.values(student.simulationsCompleted).filter(v => v).length;
    const performance = (score / PROBLEMS.length) * 100;

    return (
      <div className="max-w-2xl mx-auto text-center py-6 animate-fadeIn px-4">
        <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl border-8 border-purple-50">
          <div className="w-24 h-24 bg-purple-100 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 shadow-inner">
            {performance >= 80 ? '🏆' : performance >= 60 ? '⭐' : '💪'}
          </div>
          <h2 className="text-3xl font-black text-gray-800 mb-2">¡Increíble trabajo, {student.name}!</h2>
          <p className="text-gray-500 mb-8 font-medium">Has finalizado el recorrido por el pensamiento lógico.</p>

          <div className="grid grid-cols-2 gap-4 mb-8">
            <div className="bg-purple-50 p-6 rounded-3xl border border-purple-100">
              <span className="block text-[10px] font-black uppercase tracking-widest text-purple-400 mb-1">Simulaciones</span>
              <span className="text-3xl font-black text-purple-700">{totalSims} / 4</span>
            </div>
            <div className="bg-blue-50 p-6 rounded-3xl border border-blue-100">
              <span className="block text-[10px] font-black uppercase tracking-widest text-blue-400 mb-1">Retos Logrados</span>
              <span className="text-3xl font-black text-blue-700">{score} / {PROBLEMS.length}</span>
            </div>
          </div>

          <div className="bg-gray-50 p-8 rounded-[2rem] mb-10 text-gray-700 font-medium border-2 border-dashed border-gray-200">
            <i className="fas fa-quote-left text-gray-200 text-3xl block mb-4"></i>
            {performance === 100 ? 
              "¡Perfecto! Tu capacidad de deducción es asombrosa. Sigue cultivando esa mente lógica." : 
             performance >= 60 ? 
              "¡Muy bien! Tienes bases sólidas. Con un poco más de práctica serás un maestro del orden lógico." :
              "¡Buen intento! La lógica es como un músculo: cuanto más la entrenas, más fuerte se vuelve. ¡Sigue adelante, vas por buen camino!"
            }
          </div>

          <button 
            onClick={onRestart} 
            className="w-full py-5 bg-gradient-to-r from-purple-600 to-blue-600 text-white rounded-2xl font-black text-xl shadow-xl hover:shadow-purple-200 transform hover:-translate-y-1 active:scale-95 transition-all"
          >
            VOLVER AL INICIO
          </button>
        </div>
      </div>
    );
  }

  const p = PROBLEMS[currentStep];

  return (
    <div className="max-w-2xl mx-auto animate-slideIn px-4">
      <div className="bg-white rounded-[2.5rem] overflow-hidden shadow-2xl border border-purple-50">
        <div className="bg-gradient-to-r from-purple-600 to-blue-500 p-8 text-white">
          <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] font-black uppercase tracking-widest bg-white/20 px-3 py-1 rounded-full">Reto {currentStep + 1} de {PROBLEMS.length}</span>
            <div className="flex gap-1">
              {PROBLEMS.map((_, i) => (
                <div key={i} className={`h-1.5 w-4 rounded-full ${i <= currentStep ? 'bg-white' : 'bg-white/30'}`}></div>
              ))}
            </div>
          </div>
          <h3 className="text-2xl font-black tracking-tight">{p.title}</h3>
        </div>

        <div className="p-8 md:p-10">
          <div className="bg-blue-50 p-6 rounded-3xl mb-8 relative border-l-8 border-blue-400">
            <p className="text-gray-700 text-lg leading-relaxed font-semibold italic">"{p.question}"</p>
          </div>

          <div className="grid gap-3">
            {p.options.map(opt => (
              <button
                key={opt}
                disabled={showFeedback}
                onClick={() => { playSound('pop'); setSelectedOption(opt); }}
                className={`w-full p-5 rounded-2xl border-2 text-left font-bold transition-all transform active:scale-[0.98] ${
                  selectedOption === opt 
                    ? 'border-purple-500 bg-purple-50 text-purple-700' 
                    : 'border-gray-100 bg-white hover:border-purple-200 text-gray-600'
                }`}
              >
                <div className="flex items-center gap-4">
                  <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center shrink-0 ${selectedOption === opt ? 'bg-purple-500 border-purple-500 text-white' : 'border-gray-200'}`}>
                    {selectedOption === opt ? <i className="fas fa-check text-xs"></i> : ''}
                  </div>
                  {opt}
                </div>
              </button>
            ))}
          </div>

          {showFeedback && (
            <div className={`mt-8 p-6 rounded-3xl animate-fadeIn ${selectedOption === p.answer ? 'bg-green-50 border-2 border-green-100' : 'bg-red-50 border-2 border-red-100'}`}>
              <div className="flex items-center gap-3 mb-2">
                <i className={`fas ${selectedOption === p.answer ? 'fa-check-circle text-green-500' : 'fa-times-circle text-red-500'} text-xl`}></i>
                <span className={`font-black text-sm uppercase tracking-wider ${selectedOption === p.answer ? 'text-green-700' : 'text-red-700'}`}>
                  {selectedOption === p.answer ? '¡Correcto!' : 'Respuesta Incorrecta'}
                </span>
              </div>
              <p className="text-sm text-gray-600 font-medium leading-relaxed">{p.explanation}</p>
            </div>
          )}

          <div className="mt-10 flex justify-between items-center gap-4">
            <button 
              onClick={onBack} 
              className="text-gray-400 hover:text-gray-600 font-black text-xs uppercase tracking-widest transition-colors"
            >
              <i className="fas fa-times mr-2"></i> Salir del Reto
            </button>
            {!showFeedback ? (
              <button 
                onClick={handleVerify}
                disabled={!selectedOption}
                className="px-10 py-4 bg-purple-600 text-white rounded-2xl font-black shadow-lg hover:bg-purple-700 disabled:opacity-30 transition-all transform hover:-translate-y-1"
              >
                COMPROBAR
              </button>
            ) : (
              <button 
                onClick={handleNext}
                className="px-10 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all transform hover:-translate-y-1"
              >
                {currentStep === PROBLEMS.length - 1 ? 'VER RESULTADOS' : 'SIGUIENTE RETO'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Challenge;

import React, { useState } from 'react';
import { View, Person, StudentProfile } from './types';
import Welcome from './components/Welcome';
import CourseMenu from './components/CourseMenu';
import Theory from './components/Theory';
import HorizontalOrdering from './components/HorizontalOrdering';
import VerticalOrdering from './components/VerticalOrdering';
import CircularOrdering from './components/CircularOrdering';
import TableOrdering from './components/TableOrdering';
import Challenge from './components/Challenge';
import Footer from './components/Footer';

const INITIAL_HORIZONTAL: Person[] = [
  { id: '1', name: 'María', color: 'bg-red-400' },
  { id: '2', name: 'Juana', color: 'bg-blue-400' },
  { id: '3', name: 'Ana', color: 'bg-green-400' },
  { id: '4', name: 'Inés', color: 'bg-yellow-400' },
  { id: '5', name: 'Enma', color: 'bg-pink-400' },
];

const INITIAL_VERTICAL: Person[] = [
  { id: 'p1', name: 'Raúl', color: 'bg-orange-400' },
  { id: 'p2', name: 'Pedro', color: 'bg-indigo-400' },
  { id: 'p3', name: 'Carlos', color: 'bg-emerald-400' },
  { id: 'p4', name: 'Julio', color: 'bg-rose-400' },
];

const PEOPLE_PAR: Person[] = [
  { id: 'w', name: 'W', color: 'bg-red-400' },
  { id: 'a', name: 'A', color: 'bg-blue-400' },
  { id: 'c', name: 'C', color: 'bg-green-400' },
  { id: 'f', name: 'F', color: 'bg-yellow-400' },
  { id: 'p', name: 'P', color: 'bg-purple-400' },
  { id: 'b', name: 'B', color: 'bg-pink-400' },
  { id: 'x', name: 'X', color: 'bg-orange-400' },
  { id: 's', name: 'S', color: 'bg-indigo-400' },
];

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.WELCOME);
  const [student, setStudent] = useState<StudentProfile | null>(null);

  // Estados de simulación para persistencia durante la sesión
  const [hSlots, setHSlots] = useState<(Person | null)[]>(Array(5).fill(null));
  const [hAvailable, setHAvailable] = useState<Person[]>(INITIAL_HORIZONTAL);
  const [vFloors, setVFloors] = useState<(Person | null)[]>(Array(4).fill(null));
  const [vAvailable, setVAvailable] = useState<Person[]>(INITIAL_VERTICAL);
  const [cMode, setCMode] = useState<'PAR' | 'IMPAR'>('PAR');
  const [cSeats, setCSeats] = useState<(Person | null)[]>(Array(8).fill(null));
  const [cAvailable, setCAvailable] = useState<Person[]>(PEOPLE_PAR);
  const [tGrid, setTGrid] = useState<(string | null)[][]>(Array(4).fill(null).map(() => Array(4).fill(null)));

  const handleStart = (name: string) => {
    const newProfile: StudentProfile = {
      name,
      simulationsCompleted: { horizontal: false, vertical: false, circular: false, table: false },
      challengeScore: 0
    };
    setStudent(newProfile);

    // Registrar intento en historial local
    const history = JSON.parse(localStorage.getItem('logic_attempts') || '[]');
    localStorage.setItem('logic_attempts', JSON.stringify([...history, { 
      name, 
      timestamp: new Date().toLocaleString() 
    }]));

    setCurrentView(View.MENU);
  };

  const updateProgress = (key: keyof StudentProfile['simulationsCompleted']) => {
    if (student) {
      setStudent({
        ...student,
        simulationsCompleted: { ...student.simulationsCompleted, [key]: true }
      });
    }
  };

  const calculateProgress = () => {
    if (!student) return 0;
    const items = Object.values(student.simulationsCompleted);
    const completedCount = items.filter(v => v).length;
    return (completedCount / items.length) * 100;
  };

  const renderView = () => {
    switch (currentView) {
      case View.WELCOME:
        return <Welcome onStart={handleStart} />;
      case View.MENU:
        return <CourseMenu onSelect={() => setCurrentView(View.THEORY)} />;
      case View.THEORY:
        return <Theory onNext={() => setCurrentView(View.HORIZONTAL)} />;
      case View.HORIZONTAL:
        return (
          <HorizontalOrdering 
            slots={hSlots} setSlots={setHSlots}
            available={hAvailable} setAvailable={setHAvailable}
            onNext={() => { updateProgress('horizontal'); setCurrentView(View.VERTICAL); }} 
            onBack={() => setCurrentView(View.THEORY)}
          />
        );
      case View.VERTICAL:
        return (
          <VerticalOrdering 
            floors={vFloors} setFloors={setVFloors}
            available={vAvailable} setAvailable={setVAvailable}
            onNext={() => { updateProgress('vertical'); setCurrentView(View.CIRCULAR); }} 
            onBack={() => setCurrentView(View.HORIZONTAL)}
          />
        );
      case View.CIRCULAR:
        return (
          <CircularOrdering 
            mode={cMode} setMode={setCMode}
            seats={cSeats} setSeats={setCSeats}
            available={cAvailable} setAvailable={setCAvailable}
            onNext={() => { updateProgress('circular'); setCurrentView(View.TABLE); }} 
            onBack={() => setCurrentView(View.VERTICAL)}
          />
        );
      case View.TABLE:
        return (
          <TableOrdering 
            grid={tGrid} setGrid={setTGrid}
            onNext={() => { updateProgress('table'); setCurrentView(View.CHALLENGE); }} 
            onBack={() => setCurrentView(View.CIRCULAR)}
          />
        );
      case View.CHALLENGE:
        return (
          <Challenge 
            student={student!}
            onRestart={() => {
              setHSlots(Array(5).fill(null));
              setVFloors(Array(4).fill(null));
              setTGrid(Array(4).fill(null).map(() => Array(4).fill(null)));
              setCurrentView(View.WELCOME);
            }} 
            onBack={() => setCurrentView(View.TABLE)} 
          />
        );
      default:
        return <Welcome onStart={handleStart} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden pb-10">
      <div className="absolute inset-0 bg-pattern -z-10"></div>

      {currentView !== View.WELCOME && (
        <header className="bg-white/80 backdrop-blur-md sticky top-0 z-50 shadow-sm border-b border-purple-100">
          <div className="max-w-6xl mx-auto px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <button onClick={() => setCurrentView(View.MENU)} className="w-10 h-10 bg-purple-100 rounded-xl flex items-center justify-center text-purple-600 hover:bg-purple-600 hover:text-white transition-all">
                <i className="fas fa-home"></i>
              </button>
              <div>
                <h1 className="text-lg font-black text-gray-800 leading-none">Lógica <span className="text-purple-600">6°/7°</span></h1>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Estudiante: {student?.name}</p>
              </div>
            </div>

            <div className="flex flex-col gap-1 w-full md:max-w-[200px]">
              <div className="flex justify-between text-[9px] font-black text-gray-400 uppercase tracking-widest">
                <span>Progreso Ejemplos</span>
                <span className="text-purple-600">{Math.round(calculateProgress())}%</span>
              </div>
              <div className="h-2 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                <div 
                  className="h-full bg-gradient-to-r from-purple-500 to-blue-500 transition-all duration-1000 ease-out" 
                  style={{ width: `${calculateProgress()}%` }}
                ></div>
              </div>
            </div>
          </div>
        </header>
      )}

      <main className="flex-grow container mx-auto px-4 py-8 relative">
        {renderView()}
      </main>

      <Footer />
    </div>
  );
};

export default App;

