                          <i className="fas fa-plus text-[8px] text-gray-200 group-hover:text-blue-400 transition-colors"></i>
                        </div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Personas Disponibles */}
          <div className="flex flex-wrap md:flex-col gap-3 justify-center">
