        <div className="flex justify-between items-center mt-12 pt-8 border-t border-gray-100">
          <button onClick={onBack} className="text-gray-400 font-black text-xs uppercase tracking-widest hover:text-gray-600">
            <i className="fas fa-arrow-left mr-2"></i> Anterior
          </button>
          <div className="flex gap-2">
            {CONNECTOR_DATA.map((_, i) => (
              <div key={i} className={`h-2 w-8 rounded-full transition-all ${i === step ? 'bg-purple-600' : 'bg-gray-100'}`}></div>
            ))}
          </div>
          <button 
            onClick={showFeedback ? nextStep : undefined}
            disabled={!showFeedback}
            className="px-8 py-3 bg-purple-600 text-white rounded-2xl font-black text-xs shadow-lg disabled:opacity-30 hover:bg-purple-700 transition-all"
          >
            {step === CONNECTOR_DATA.length - 1 ? 'CONTINUAR A INFERENCIAS' : 'SIGUIENTE CONECTOR'}
          </button>
        </div>
      </div>
    </div>
  );
};

