          <button onClick={onBack} className="text-gray-400 font-black text-xs uppercase tracking-widest hover:text-gray-600">
            <i className="fas fa-arrow-left mr-2"></i> Anterior
          </button>
          <div className="flex gap-2">
            {INFERENCE_DATA.map((_, i) => (
              <div key={i} className={`h-2 w-8 rounded-full transition-all ${i === step ? 'bg-emerald-500' : 'bg-gray-100'}`}></div>
            ))}
          </div>
          <button 
            onClick={showFeedback ? nextStep : undefined}
            disabled={!showFeedback}
            className="px-10 py-4 bg-emerald-600 text-white rounded-2xl font-black text-xs shadow-lg disabled:opacity-30 hover:bg-emerald-700 transition-all"
          >
            {step === INFERENCE_DATA.length - 1 ? '¡LISTO PARA LOS RETOS!' : 'SIGUIENTE REGLA'}
          </button>
        </div>
      </div>
    </div>
  );
};

