const Challenge: React.FC<Props> = ({ student, onRestart, onBack }) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [score, setScore] = useState(0);
  const [finished, setFinished] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showFeedback, setShowFeedback] = useState(false);

  const handleVerify = () => {
    if (selectedOption === PROBLEMS[currentStep].answer) {
      playSound('success');
      setScore(s => s + 1);
    } else {
      playSound('error');
    }
    setShowFeedback(true);
  };

  const handleNext = () => {
    playSound('pop');
    if (currentStep < PROBLEMS.length - 1) {
      setCurrentStep(s => s + 1);
      setSelectedOption(null);
      setShowFeedback(false);
    } else {
      setFinished(true);
      playSound('finish');
    }
  };

  if (finished) {
    const totalSims = Object.values(student.simulationsCompleted).filter(v => v).length;
    const performance = (score / PROBLEMS.length) * 100;

    return (
      <div className="max-w-2xl mx-auto text-center py-6 animate-fadeIn px-4">
        <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl border-8 border-purple-50">
          <div className="w-24 h-24 bg-purple-100 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 shadow-inner">
            {performance >= 80 ? '🏆' : performance >= 60 ? '⭐' : '💪'}
          </div>
          <h2 className="text-3xl font-black text-gray-800 mb-2">¡Increíble trabajo, {student.name}!</h2>

          <div className="mb-8">
            <span className="inline-block px-4 py-1.5 bg-purple-100 text-purple-700 rounded-full text-[10px] font-black uppercase tracking-widest mb-2">
              Resultados de Aprendizaje
            </span>
            <p className="text-gray-500 font-bold text-sm">Capítulo 1: Pensamiento Verbal</p>
            <p className="text-purple-600 font-black text-xs uppercase">Módulo: Lógica Proposicional & Ordenamiento</p>
          </div>

          <div className="grid grid-cols-2 gap-4 mb-8">
            <div className="bg-purple-50 p-6 rounded-3xl border border-purple-100">
              <span className="block text-[10px] font-black uppercase tracking-widest text-purple-400 mb-1">Simulaciones Logradas</span>
              <span className="text-2xl font-black text-purple-700">{totalSims} / 7</span>
              <p className="text-[8px] text-gray-400 mt-1 uppercase">Incluye Teoría Interactiva</p>
            </div>
            <div className="bg-blue-50 p-6 rounded-3xl border border-blue-100">
              <span className="block text-[10px] font-black uppercase tracking-widest text-blue-400 mb-1">Retos de Evaluación</span>
              <span className="text-2xl font-black text-blue-700">{score} / {PROBLEMS.length}</span>
              <p className="text-[8px] text-gray-400 mt-1 uppercase">Promedio: {Math.round(performance)}%</p>
            </div>
          </div>

          <div className="bg-gray-50 p-8 rounded-[2rem] mb-10 text-gray-700 font-medium border-2 border-dashed border-gray-200">
            <i className="fas fa-quote-left text-gray-200 text-3xl block mb-4"></i>
            {performance === 100 ? 
              "¡Perfecto! Tu capacidad de deducción es asombrosa. Sigue cultivando esa mente lógica." : 
             performance >= 60 ? 
              "¡Muy bien! Tienes bases sólidas. Con un poco más de práctica serás un maestro del orden lógico." :
              "¡Buen intento! La lógica es como un músculo: cuanto más la entrenas, más fuerte se vuelve. ¡Incluso si hoy no acertaste todas, el esfuerzo es lo que te hace aprender!"
            }
          </div>

          <button 
            onClick={onRestart} 
            className="w-full py-5 bg-gradient-to-r from-purple-600 to-blue-600 text-white rounded-2xl font-black text-xl shadow-xl hover:shadow-purple-200 transform hover:-translate-y-1 active:scale-95 transition-all"
          >
            VOLVER AL MENÚ PRINCIPAL
          </button>
        </div>
      </div>
    );
  }

  const p = PROBLEMS[currentStep];

  return (
    <div className="max-w-2xl mx-auto animate-slideIn px-4">
      <div className="bg-white rounded-[2.5rem] overflow-hidden shadow-2xl border border-purple-50">
        <div className="bg-gradient-to-r from-purple-600 to-blue-500 p-8 text-white">
          <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] font-black uppercase tracking-widest bg-white/20 px-3 py-1 rounded-full">Evaluación Final</span>
            <div className="flex gap-1">
              {PROBLEMS.map((_, i) => (
                <div key={i} className={`h-1.5 w-4 rounded-full ${i <= currentStep ? 'bg-white' : 'bg-white/30'}`}></div>
              ))}
            </div>
          </div>
          <h3 className="text-2xl font-black tracking-tight">{p.title}</h3>
        </div>

        <div className="p-8 md:p-10">
          <div className="bg-blue-50 p-6 rounded-3xl mb-8 relative border-l-8 border-blue-400">
            <p className="text-gray-700 text-lg leading-relaxed font-semibold italic">"{p.question}"</p>
          </div>

          <div className="grid gap-3">
            {p.options.map(opt => (
              <button
                key={opt}
                disabled={showFeedback}
                onClick={() => { playSound('pop'); setSelectedOption(opt); }}
                className={`w-full p-5 rounded-2xl border-2 text-left font-bold transition-all transform active:scale-[0.98] ${
                  selectedOption === opt 
                    ? 'border-purple-500 bg-purple-50 text-purple-700' 
                    : 'border-gray-100 bg-white hover:border-purple-200 text-gray-600'
                }`}
              >
                <div className="flex items-center gap-4">
                  <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center shrink-0 ${selectedOption === opt ? 'bg-purple-500 border-purple-500 text-white' : 'border-gray-200'}`}>
                    {selectedOption === opt ? <i className="fas fa-check text-xs"></i> : ''}
                  </div>
                  {opt}
                </div>
              </button>
            ))}
          </div>

          {showFeedback && (
            <div className={`mt-8 p-6 rounded-3xl animate-fadeIn ${selectedOption === p.answer ? 'bg-green-50 border-2 border-green-100' : 'bg-red-50 border-2 border-red-100'}`}>
              <div className="flex items-center gap-3 mb-2">
                <i className={`fas ${selectedOption === p.answer ? 'fa-check-circle text-green-500' : 'fa-times-circle text-red-500'} text-xl`}></i>
                <span className={`font-black text-sm uppercase tracking-wider ${selectedOption === p.answer ? 'text-green-700' : 'text-red-700'}`}>
                  {selectedOption === p.answer ? '¡Correcto!' : 'Respuesta Incorrecta'}
                </span>
              </div>
              <p className="text-sm text-gray-600 font-medium leading-relaxed">{p.explanation}</p>
            </div>
          )}

          <div className="mt-10 flex justify-between items-center gap-4">
            <button 
              onClick={() => { playSound('pop'); onBack(); }} 
              className="text-gray-400 hover:text-gray-600 font-black text-xs uppercase tracking-widest transition-colors"
            >
              <i className="fas fa-times mr-2"></i> Salir del Reto
            </button>
            {!showFeedback ? (
              <button 
                onClick={handleVerify}
                disabled={!selectedOption}
                className="px-10 py-4 bg-purple-600 text-white rounded-2xl font-black shadow-lg hover:bg-purple-700 disabled:opacity-30 transition-all transform hover:-translate-y-1"
              >
                COMPROBAR
              </button>
            ) : (
              <button 
                onClick={handleNext}
                className="px-10 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 transition-all transform hover:-translate-y-1"
              >
                {currentStep === PROBLEMS.length - 1 ? 'VER RESULTADOS' : 'SIGUIENTE RETO'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

