const PropositionIdentifier: React.FC<Props> = ({ onFinish, onBack }) => {
  const [current, setCurrent] = useState(0);
  const [feedback, setFeedback] = useState<{ msg: string; correct: boolean } | null>(null);
  const [score, setScore] = useState(0);

  const handleChoice = (type: string) => {
    const item = ITEMS[current];
    if (type === item.type) {
      playSound('success');
      setFeedback({ msg: `¡Bien hecho! ${item.explanation}`, correct: true });
      setScore(s => s + 1);
    } else {
      playSound('error');
      setFeedback({ msg: `Ups... ${item.explanation}`, correct: false });
    }
  };

  const nextItem = () => {
    playSound('pop');
    setFeedback(null);
    if (current < ITEMS.length - 1) {
      setCurrent(c => c + 1);
    } else {
      onFinish(score);
    }
  };

  const item = ITEMS[current];

  return (
    <div className="max-w-4xl mx-auto animate-slideIn px-4">
      <div className="bg-white p-8 md:p-12 rounded-[3rem] shadow-2xl border-4 border-purple-50">
        <header className="mb-10">
          <div className="flex justify-between items-center mb-6">
            <span className="text-[10px] font-black uppercase tracking-widest text-purple-400 bg-purple-50 px-4 py-1.5 rounded-full">Reto 1: Clasificación</span>
            <span className="text-xs font-black text-gray-400">PUNTAJE: {score}/{ITEMS.length}</span>
          </div>
          <h2 className="text-2xl font-black text-gray-800">El Filtro Lógico</h2>
          <p className="text-gray-500 text-sm font-medium">Clasifica cada enunciado según su estructura lógica.</p>
        </header>

        <div className="bg-gray-50 p-10 rounded-[2.5rem] mb-10 min-h-[160px] flex items-center justify-center border-4 border-dashed border-gray-100 relative overflow-hidden">
           <div className="absolute top-4 left-4 text-purple-200 text-4xl opacity-50"><i className="fas fa-quote-left"></i></div>
           <p className="text-xl md:text-2xl font-bold text-gray-700 text-center leading-relaxed italic z-10 px-4">
             {item.text}
           </p>
        </div>

        {!feedback ? (
          <div className="grid md:grid-cols-3 gap-4">
            <button 
              onClick={() => handleChoice('SIMPLE')}
              className="p-6 bg-white border-2 border-blue-100 hover:border-blue-400 rounded-3xl font-black text-blue-600 transition-all hover:shadow-lg transform active:scale-95"
            >
              <i className="fas fa-atom block text-2xl mb-2"></i>
              PROPOSICIÓN SIMPLE
            </button>
            <button 
              onClick={() => handleChoice('COMP')}
              className="p-6 bg-white border-2 border-purple-100 hover:border-purple-400 rounded-3xl font-black text-purple-600 transition-all hover:shadow-lg transform active:scale-95"
            >
              <i className="fas fa-project-diagram block text-2xl mb-2"></i>
              PROPOSICIÓN COMPUESTA
            </button>
            <button 
              onClick={() => handleChoice('NONE')}
              className="p-6 bg-white border-2 border-red-100 hover:border-red-400 rounded-3xl font-black text-red-600 transition-all hover:shadow-lg transform active:scale-95"
            >
              <i className="fas fa-ban block text-2xl mb-2"></i>
              NO ES PROPOSICIÓN
            </button>
          </div>
        ) : (
          <div className={`p-8 rounded-[2rem] text-center animate-fadeIn ${feedback.correct ? 'bg-green-50 border-2 border-green-100' : 'bg-red-50 border-2 border-red-100'}`}>
            <div className={`w-12 h-12 rounded-full mx-auto flex items-center justify-center text-xl mb-4 text-white ${feedback.correct ? 'bg-green-500' : 'bg-red-500'}`}>
               <i className={`fas ${feedback.correct ? 'fa-check' : 'fa-info'}`}></i>
            </div>
            <p className={`font-black text-lg mb-2 ${feedback.correct ? 'text-green-700' : 'text-red-700'}`}>
              {feedback.correct ? '¡Correcto!' : 'Explicación:'}
            </p>
            <p className="text-gray-600 font-medium mb-6 px-4">{feedback.msg}</p>
            <button 
              onClick={nextItem}
              className="px-10 py-3 bg-gray-800 text-white rounded-2xl font-black text-sm hover:bg-black transition-all"
            >
              {current === ITEMS.length - 1 ? 'FINALIZAR RETO' : 'CONTINUAR'} <i className="fas fa-arrow-right ml-2"></i>
            </button>
          </div>
        )}

        <div className="mt-12 pt-6 border-t border-gray-100 flex justify-between items-center">
           <button onClick={onBack} className="text-gray-400 hover:text-gray-600 text-xs font-black uppercase tracking-widest transition-colors">
             <i className="fas fa-times mr-1"></i> Abortar Reto
           </button>
           <div className="flex gap-1">
             {ITEMS.map((_, i) => (
               <div key={i} className={`h-1.5 w-4 rounded-full transition-all ${i === current ? 'bg-purple-600 w-8' : i < current ? 'bg-purple-200' : 'bg-gray-100'}`}></div>
             ))}
           </div>
        </div>
      </div>
    </div>
  );
