      setScore(s => s + 1);
    } else {
      playSound('error');
      setFeedback("Incorrecto. Mira las pistas de ayuda abajo.");
    }
  };

  const nextTask = () => {
    playSound('pop');
    setFeedback(null);
    if (current < TASKS.length - 1) {
      setCurrent(c => c + 1);
    } else {
      onFinish(score);
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-slideIn px-4">
