        inference: boolean;
        quantifiers: boolean; // Nuevo: Seguimiento de cuantificadores
      };
      challengeScores: {
        identification: number;
        symbolization: number;
        inference: number;
        quantifiers: number; // Nuevo: Puntaje del juego
      };
    };
  };
}

