import React, { useState, useEffect } from 'react';
import { playSound } from '../audio';

interface Props {
  onFinish: (score: number) => void;
  onBack: () => void;
}

enum GameState {
  INTRO,
  LEVEL1, // Identificación
  LEVEL2, // Simbolización
  LEVEL3, // Negación/Equivalencia
  SUMMARY
}

const LEVEL1_DATA = [
  { text: "Todos los planetas giran.", type: "U" },
  { text: "Existe un alienígena azul.", type: "E" },
  { text: "Cualquier estrella brilla.", type: "U" },
  { text: "Algunos cometas son de hielo.", type: "E" },
  { text: "Ningún humano vive en Marte.", type: "U" }, // Universal Negativo
  { text: "Hay al menos un astronauta perdido.", type: "E" }
];

const LEVEL2_DATA = [
  { phrase: "Todos los robots (R) son lentos (L)", correct: ["∀", "x", "R(x) → L(x)"] },
  { phrase: "Existe algún humano (H) que es sabio (S)", correct: ["∃", "x", "H(x) ∧ S(x)"] }
];

const LEVEL3_DATA = [
  { q: "Niega: 'Todos los aliens son verdes'", options: ["Algunos aliens no son verdes", "Ningún alien es verde", "Todos los aliens son rojos"], correct: 0 },
  { q: "Niega: 'Existe un planeta habitado'", options: ["Ningún planeta está habitado", "Todos los planetas están habitados", "Algunos planetas están habitados"], correct: 0 },
  { q: "Equivalente a: 'No todos los soles brillan'", options: ["Existe al menos un sol que no brilla", "Ningún sol brilla", "Todos los soles brillan"], correct: 0 }
];

const QuantifiersGame: React.FC<Props> = ({ onFinish, onBack }) => {
  const [state, setState] = useState<GameState>(GameState.INTRO);
  const [score, setScore] = useState(0);
  const [energy, setEnergy] = useState(100);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [assembledFormula, setAssembledFormula] = useState<string[]>([]);

  // Efectos visuales de "universo"
  useEffect(() => {
    if (energy <= 0) {
      playSound('error');
      alert("¡Energía agotada! Inténtalo de nuevo.");
      onBack();
    }
  }, [energy]);

  const handleLevel1 = (choice: "U" | "E") => {
    const item = LEVEL1_DATA[currentIdx];
    if (choice === item.type) {
      playSound('success');
      setScore(s => s + 10);
    } else {
      playSound('error');
      setEnergy(e => e - 15);
    }

    if (currentIdx < LEVEL1_DATA.length - 1) {
      setCurrentIdx(currentIdx + 1);
    } else {
      setCurrentIdx(0);
      setState(GameState.LEVEL2);
    }
  };

  const addToFormula = (val: string) => {
    playSound('pop');
    setAssembledFormula([...assembledFormula, val]);
  };

  const checkFormula = () => {
    const item = LEVEL2_DATA[currentIdx];
    const isCorrect = JSON.stringify(assembledFormula) === JSON.stringify(item.correct);

    if (isCorrect) {
      playSound('success');
      setScore(s => s + 20);
      if (currentIdx < LEVEL2_DATA.length - 1) {
        setCurrentIdx(currentIdx + 1);
        setAssembledFormula([]);
      } else {
        setCurrentIdx(0);
        setState(GameState.LEVEL3);
      }
    } else {
      playSound('error');
      setEnergy(e => e - 20);
      setAssembledFormula([]);
    }
  };

  const handleLevel3 = (idx: number) => {
    const item = LEVEL3_DATA[currentIdx];
    if (idx === item.correct) {
      playSound('success');
      setScore(s => s + 30);
    } else {
      playSound('error');
      setEnergy(e => e - 25);
    }

    if (currentIdx < LEVEL3_DATA.length - 1) {
      setCurrentIdx(currentIdx + 1);
    } else {
      setState(GameState.SUMMARY);
    }
  };

  const renderIntro = () => (
    <div className="text-center space-y-8 py-10">
      <div className="relative inline-block">
        <div className="w-32 h-32 bg-pink-500 rounded-full flex items-center justify-center text-white text-5xl shadow-[0_0_50px_rgba(236,72,153,0.5)] animate-pulse">
          <i className="fas fa-infinity"></i>
        </div>
      </div>
      <h2 className="text-4xl font-black text-gray-800 tracking-tighter uppercase">Quantifier Quest</h2>
      <p className="text-gray-500 max-w-md mx-auto font-medium">
        ¡Bienvenido recluta! Tu misión es restaurar el orden lógico en la nebulosa de los cuantificadores. Supera los 3 niveles para ganar.
      </p>
      <button 
        onClick={() => { playSound('pop'); setState(GameState.LEVEL1); }}
        className="px-12 py-5 bg-pink-600 text-white rounded-2xl font-black text-xl shadow-xl hover:bg-pink-700 hover:scale-105 transition-all"
      >
        INICIAR MISIÓN
      </button>
    </div>
  );

  const renderLevel1 = () => (
    <div className="space-y-10">
      <header className="flex justify-between items-center text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">
        <span>Nivel 1: Radar Estelar</span>
        <span className="text-pink-500">Progreso: {currentIdx + 1}/{LEVEL1_DATA.length}</span>
      </header>

      <div className="bg-gray-900 p-12 rounded-[3rem] text-center shadow-inner border-4 border-gray-800 relative overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-pink-500/10 via-transparent to-transparent opacity-50"></div>
        <p className="text-2xl md:text-3xl font-black text-white italic relative z-10 leading-relaxed">
          "{LEVEL1_DATA[currentIdx].text}"
        </p>
      </div>

      <div className="grid grid-cols-2 gap-6">
        <button 
          onClick={() => handleLevel1("U")}
          className="p-8 bg-white border-4 border-blue-100 hover:border-blue-500 rounded-[2.5rem] flex flex-col items-center gap-4 group transition-all"
        >
          <span className="text-5xl font-black text-blue-600 group-hover:scale-110 transition-transform">∀</span>
          <span className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Universal</span>
        </button>
        <button 
          onClick={() => handleLevel1("E")}
          className="p-8 bg-white border-4 border-purple-100 hover:border-purple-500 rounded-[2.5rem] flex flex-col items-center gap-4 group transition-all"
        >
          <span className="text-5xl font-black text-purple-600 group-hover:scale-110 transition-transform">∃</span>
          <span className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Existencial</span>
        </button>
      </div>
    </div>
  );

  const renderLevel2 = () => {
    const symbols = ["∀", "∃", "x", "y", "R(x) → L(x)", "H(x) ∧ S(x)", "¬"];
    return (
      <div className="space-y-8">
        <header className="text-center">
          <span className="text-[10px] font-black uppercase text-gray-400">Nivel 2: Traductor Galáctico</span>
          <h3 className="text-xl font-bold text-gray-800 mt-2">Traduce a Símbolos</h3>
        </header>

        <div className="bg-pink-50 p-6 rounded-[2rem] border-2 border-pink-200 text-center">
          <p className="font-bold text-pink-900 italic">"{LEVEL2_DATA[currentIdx].phrase}"</p>
        </div>

        <div className="bg-gray-800 min-h-[80px] p-4 rounded-2xl flex items-center justify-center gap-2 border-4 border-gray-700 shadow-inner">
          {assembledFormula.length === 0 && <span className="text-gray-500 font-mono text-xs">Ensambla la fórmula...</span>}
          {assembledFormula.map((f, i) => (
            <span key={i} className="bg-pink-600 text-white px-3 py-1 rounded-lg font-black text-sm animate-pop">{f}</span>
          ))}
        </div>

        <div className="flex flex-wrap gap-2 justify-center">
          {symbols.map(s => (
            <button 
              key={s} 
              onClick={() => addToFormula(s)}
              className="px-4 py-2 bg-white border-2 border-gray-100 rounded-xl font-black text-gray-600 hover:border-pink-400 hover:text-pink-600 transition-all active:scale-95"
            >
              {s}
            </button>
          ))}
        </div>

        <div className="flex justify-center gap-4">
          <button onClick={() => setAssembledFormula([])} className="text-[10px] font-black text-gray-400 uppercase">Borrar todo</button>
          <button 
            onClick={checkFormula}
            disabled={assembledFormula.length === 0}
            className="px-10 py-3 bg-gray-800 text-white rounded-xl font-black shadow-lg disabled:opacity-20 transition-all"
          >
            VALIDAR SECUENCIA
          </button>
        </div>
      </div>
    );
  };

  const renderLevel3 = () => (
    <div className="space-y-8">
       <header className="text-center">
          <span className="text-[10px] font-black uppercase text-gray-400">Nivel 3: Escudo de Negación</span>
          <h3 className="text-xl font-bold text-gray-800 mt-2">Equivalencias y Negación</h3>
        </header>

        <div className="bg-emerald-600 p-10 rounded-[2.5rem] text-white text-center shadow-xl border-b-8 border-emerald-800">
          <p className="text-xl font-bold italic">"{LEVEL3_DATA[currentIdx].q}"</p>
        </div>

        <div className="grid gap-3">
          {LEVEL3_DATA[currentIdx].options.map((opt, i) => (
            <button
              key={i}
              onClick={() => handleLevel3(i)}
              className="p-5 bg-white border-2 border-gray-100 hover:border-emerald-500 rounded-2xl text-left font-bold text-gray-700 transition-all hover:bg-emerald-50 active:scale-95 flex items-center gap-4"
            >
              <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-[10px] font-black text-gray-400 shrink-0">{i+1}</div>
              {opt}
            </button>
          ))}
        </div>
    </div>
  );

  const renderSummary = () => (
    <div className="text-center space-y-8 py-10 animate-fadeIn">
      <div className="w-40 h-40 bg-gradient-to-tr from-yellow-400 to-orange-500 rounded-full flex items-center justify-center text-white text-6xl shadow-2xl border-8 border-white mx-auto">
        <i className="fas fa-trophy"></i>
      </div>
      <div>
        <h2 className="text-3xl font-black text-gray-800">¡MISIÓN CUMPLIDA!</h2>
        <p className="text-gray-500 font-medium">Has restaurado la lógica del cuadrante.</p>
      </div>
      <div className="bg-gray-50 p-6 rounded-[2.5rem] inline-block px-12 border-2 border-gray-100">
        <span className="text-[10px] font-black uppercase text-gray-400 block mb-1">Puntaje Obtenido</span>
        <span className="text-4xl font-black text-pink-600">{score} pts</span>
      </div>
      <div>
        <button 
          onClick={() => { playSound('finish'); onFinish(score); }}
          className="px-12 py-5 bg-gray-800 text-white rounded-2xl font-black shadow-xl hover:bg-black transition-all"
        >
          FINALIZAR Y VER REPORTE
        </button>
      </div>
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto animate-fadeIn px-4">
      <div className="bg-white rounded-[3rem] shadow-2xl border-4 border-pink-50 overflow-hidden">
        {/* Barra de Estado Superior */}
        {state !== GameState.INTRO && state !== GameState.SUMMARY && (
          <div className="bg-gray-900 p-4 px-8 flex justify-between items-center text-white">
            <div className="flex items-center gap-4">
              <div className="w-32 h-3 bg-gray-700 rounded-full overflow-hidden border border-gray-600">
                <div 
                  className={`h-full transition-all duration-500 ${energy > 50 ? 'bg-emerald-500' : energy > 20 ? 'bg-yellow-500' : 'bg-red-500'}`}
                  style={{ width: `${energy}%` }}
                ></div>
              </div>
              <span className="text-[8px] font-black uppercase tracking-widest text-gray-400">Energía Vital</span>
            </div>
            <div className="flex items-center gap-6">
               <div className="text-right">
                  <span className="text-[8px] font-black uppercase opacity-40 block leading-none">Puntaje</span>
                  <span className="text-xl font-black text-pink-400">{score}</span>
               </div>
               <button onClick={onBack} className="text-xs text-gray-500 hover:text-white transition-colors"><i className="fas fa-times"></i></button>
            </div>
          </div>
        )}

        <div className="p-8 md:p-12">
          {state === GameState.INTRO && renderIntro()}
          {state === GameState.LEVEL1 && renderLevel1()}
          {state === GameState.LEVEL2 && renderLevel2()}
          {state === GameState.LEVEL3 && renderLevel3()}
          {state === GameState.SUMMARY && renderSummary()}
        </div>
      </div>
    </div>
  );
};

