import React, { useState, useEffect } from 'react';
import { playSound } from '../audio';

interface Props {
  onFinish: (score: number) => void;
  onBack: () => void;
}

enum MicrobitLevel {
  TUTORIAL,
  LEVEL1, // P: Si se agita
  LEVEL2, // P ∧ Q: Si presiona A y B
  LEVEL3, // P ∨ Q: Si presiona A o se agita
  FINAL
}

const MicrobitGame: React.FC<Props> = ({ onFinish, onBack }) => {
  const [level, setLevel] = useState<MicrobitLevel>(MicrobitLevel.TUTORIAL);
  const [isA, setIsA] = useState(false);
  const [isB, setIsB] = useState(false);
  const [isShaking, setIsShaking] = useState(false);
  const [score, setScore] = useState(0);
  const [blockSelection, setBlockSelection] = useState<string | null>(null);
  const [showResult, setShowResult] = useState(false);

  // Simulación de "Agitar"
  const triggerShake = () => {
    playSound('pop');
    setIsShaking(true);
    setTimeout(() => setIsShaking(false), 800);
  };

  const checkLogic = () => {
    let success = false;
    switch (level) {
      case MicrobitLevel.LEVEL1:
        // Misión: Programar alerta si se detecta movimiento (Agitado)
        if (blockSelection === 'SHAKE' && isShaking) success = true;
        break;
      case MicrobitLevel.LEVEL2:
        // Misión: Llave de seguridad (A y B)
        if (blockSelection === 'A_AND_B' && isA && isB) success = true;
        break;
      case MicrobitLevel.LEVEL3:
        // Misión: Alarma de emergencia (A o Agitado)
        if (blockSelection === 'A_OR_SHAKE' && (isA || isShaking)) success = true;
        break;
    }

    if (success && !showResult) {
      playSound('success');
      setShowResult(true);
      setScore(s => s + 50);
    }
  };

  useEffect(() => {
    checkLogic();
  }, [isA, isB, isShaking]);

  const nextLevel = () => {
    playSound('pop');
    setShowResult(false);
    setBlockSelection(null);
    setIsA(false);
    setIsB(false);
    if (level === MicrobitLevel.LEVEL1) setLevel(MicrobitLevel.LEVEL2);
    else if (level === MicrobitLevel.LEVEL2) setLevel(MicrobitLevel.LEVEL3);
    else setLevel(MicrobitLevel.FINAL);
  };

  const renderMicrobit = () => (
    <div className={`relative w-64 h-52 bg-gray-900 rounded-3xl border-4 border-gray-800 shadow-2xl flex flex-col items-center justify-center transition-transform ${isShaking ? 'animate-bounce' : ''}`}>
