          onMouseDown={() => setIsA(true)} onMouseUp={() => setIsA(false)}
          className={`w-10 h-10 rounded-full border-4 font-black flex items-center justify-center text-xs transition-all ${isA ? 'bg-blue-600 border-blue-400 text-white scale-90' : 'bg-gray-700 border-gray-600 text-gray-400'}`}
        >A</button>
        <span className="text-[8px] font-black text-gray-500 uppercase tracking-widest">Botón</span>
      </div>

      <div className="absolute right-4 top-1/2 -translate-y-1/2 flex flex-col items-center gap-1">
        <button 
          onMouseDown={() => setIsB(true)} onMouseUp={() => setIsB(false)}
          className={`w-10 h-10 rounded-full border-4 font-black flex items-center justify-center text-xs transition-all ${isB ? 'bg-blue-600 border-blue-400 text-white scale-90' : 'bg-gray-700 border-gray-600 text-gray-400'}`}
        >B</button>
        <span className="text-[8px] font-black text-gray-500 uppercase tracking-widest">Botón</span>
      </div>

      <div className="absolute bottom-4 text-[10px] font-black text-gray-600 flex items-center gap-2">
        <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
        POWER ON
      </div>
    </div>
  );

  const renderTutorial = () => (
    <div className="text-center space-y-8 py-6 animate-fadeIn">
      <div className="w-32 h-32 bg-emerald-500 rounded-[2.5rem] flex items-center justify-center text-white text-5xl shadow-2xl mx-auto rotate-12">
        <i className="fas fa-microchip"></i>
      </div>
      <h2 className="text-3xl font-black text-gray-800">El Despertar del Robot</h2>
      <p className="text-gray-500 max-w-md mx-auto font-medium">
