  const renderLevel = (mission: string, blocks: { id: string, text: string }[]) => (
    <div className="space-y-10 animate-slideIn">
      <header className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-gray-400">
        <span>Misión de Lógica Física</span>
        <span className="text-emerald-500">Reparación: {level}/3</span>
      </header>

      <div className="grid md:grid-cols-2 gap-10 items-center">
        {/* Zona del Simulador */}
        <div className="flex flex-col items-center gap-8">
            <h4 className="text-sm font-black text-gray-400 uppercase tracking-widest">Simulador en Tiempo Real</h4>
            {renderMicrobit()}
            <button 
