            </div>
            <button onClick={nextLevel} className="px-8 py-4 bg-white text-emerald-600 rounded-2xl font-black text-sm hover:scale-105 transition-all">
                SIGUIENTE NIVEL <i className="fas fa-arrow-right ml-2"></i>
            </button>
