      </button>
    </div>
  );

  const renderLevel = (mission: string, blocks: { id: string, text: string }[]) => (
    <div className="space-y-10 animate-slideIn">
      <div className="bg-gray-100 p-2 rounded-full flex justify-between items-center px-6">
