            </div>

            <div className="bg-gray-50 p-6 rounded-[2.5rem] border-4 border-dashed border-gray-200">
                <span className="text-[10px] font-black text-gray-400 uppercase mb-4 block text-center">Caja de Herramientas Lógicas</span>
                <div className="grid grid-cols-1 gap-2">
                    {blocks.map(b => (
