                            <i className={`fas fa-puzzle-piece ${blockSelection === b.id ? 'text-indigo-300' : 'text-gray-200 group-hover:text-indigo-200'}`}></i>
                        </button>
                    ))}
                </div>
            </div>

            <div className="bg-gray-900 p-6 rounded-3xl text-white shadow-inner">
                <div className="flex items-center gap-3">
                    <span className="bg-indigo-500 px-3 py-1 rounded-lg text-[10px] font-black uppercase">IF</span>
