            </div>
        </div>
      </div>

      {showResult && (
        <div className="bg-emerald-600 p-8 rounded-[3rem] text-white flex flex-col md:flex-row items-center justify-between animate-fadeIn shadow-2xl gap-6 border-b-8 border-emerald-800">
