            [
              { id: 'A_OR_B', text: 'P ∨ R (A o B)' },
              { id: 'A_AND_B', text: 'P ∧ R (A y B)' },
              { id: 'NOT_A', text: '¬P (No A)' }
            ]
          )}
          {level === MicrobitLevel.LEVEL3 && renderLevel(
